import type { Article } from '../../../common/types/law.types';

export const ARTICLES_CONST_SANTA_CRUZ: Article[] = [
  { id: 'const-santa-cruz-art-1', lawId: 'const-santa-cruz', number: '1', title: '', originalText: `La Provincia de Santa Cruz, con los límites que por derecho le corresponden, es parte indestructible e inseparable de la Nación Argentina. La Constitución Nacional y las Leyes Nacionales que en su conformidad se dicten son su Ley Suprema. Para el libre ejercicio de los poderes y derechos no delegados expresamente a la Nación, se organiza de acuerdo a la forma representativa y republicana.`, currentText: `La Provincia de Santa Cruz, con los límites que por derecho le corresponden, es parte indestructible e inseparable de la Nación Argentina. La Constitución Nacional y las Leyes Nacionales que en su conformidad se dicten son su Ley Suprema. Para el libre ejercicio de los poderes y derechos no delegados expresamente a la Nación, se organiza de acuerdo a la forma representativa y republicana.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-2', lawId: 'const-santa-cruz', number: '2', title: '', originalText: `El Gobierno Provincial residirá en la ciudad de Río Gallegos que se declara capital de la Provincia.`, currentText: `El Gobierno Provincial residirá en la ciudad de Río Gallegos que se declara capital de la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 1, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-3', lawId: 'const-santa-cruz', number: '3', title: '', originalText: `Todos los habitantes de la Provincia de Santa Cruz gozarán en ella de los derechos y garantías que la Constitución Nacional otorga, los que seran asegurados por los poderes provinciales.`, currentText: `Todos los habitantes de la Provincia de Santa Cruz gozarán en ella de los derechos y garantías que la Constitución Nacional otorga, los que seran asegurados por los poderes provinciales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 2, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-4', lawId: 'const-santa-cruz', number: '4', title: '', originalText: `La Provincia reconoce los derechos de la Iglesia Católica. No sostendrá ni favorecerá culto alguno, pero podrá prestar su apoyo a la labor cultural o científica que cumplan entidades religiosas, jurídicamente organizadas, sin que ello signifique atribuirse sobre las mismas ningún derecho.`, currentText: `La Provincia reconoce los derechos de la Iglesia Católica. No sostendrá ni favorecerá culto alguno, pero podrá prestar su apoyo a la labor cultural o científica que cumplan entidades religiosas, jurídicamente organizadas, sin que ello signifique atribuirse sobre las mismas ningún derecho.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 3, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-5', lawId: 'const-santa-cruz', number: '5', title: '', originalText: `No se admitirán otras inhabilitaciones para el ejercicio de la función pública o gremial, que las que surjan de esta Constitución y las que se funden en sentencia judicial.`, currentText: `No se admitirán otras inhabilitaciones para el ejercicio de la función pública o gremial, que las que surjan de esta Constitución y las que se funden en sentencia judicial.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 4, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-6', lawId: 'const-santa-cruz', number: '6', title: '', originalText: `En ningún caso podrán las autoridades de la Provincia suspender la observancia de esta Constitución ni de la Nacional, ni la efectividad de las garantías y derechos establecidos en ambas. En caso de Intervención Federal, los actos practicados por el Interventor serán válidos si hubieren sido realizados conforme a esta Constitución y leyes de la Provincia.`, currentText: `En ningún caso podrán las autoridades de la Provincia suspender la observancia de esta Constitución ni de la Nacional, ni la efectividad de las garantías y derechos establecidos en ambas. En caso de Intervención Federal, los actos practicados por el Interventor serán válidos si hubieren sido realizados conforme a esta Constitución y leyes de la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 5, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-7', lawId: 'const-santa-cruz', number: '7', title: '', originalText: `El pueblo de la Provincia sólo gobierna por medio de sus representantes y autoridades, en la forma establecida por esta Constitución, pero conserva los derechos de reunión pacífica y de petición individual o colectiva.`, currentText: `El pueblo de la Provincia sólo gobierna por medio de sus representantes y autoridades, en la forma establecida por esta Constitución, pero conserva los derechos de reunión pacífica y de petición individual o colectiva.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 6, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-8', lawId: 'const-santa-cruz', number: '8', title: '', originalText: `La enumeración y reconocimiento de derechos que contiene esta Constitución expresamente, o implícitamente por contenerlos la Nacional, no importan denegacion de los demás que deriven de la condición natural del hombre, de la forma democrática de gobierno y de la justicia social.`, currentText: `La enumeración y reconocimiento de derechos que contiene esta Constitución expresamente, o implícitamente por contenerlos la Nacional, no importan denegacion de los demás que deriven de la condición natural del hombre, de la forma democrática de gobierno y de la justicia social.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 7, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-9', lawId: 'const-santa-cruz', number: '9', title: '', originalText: `Toda norma legal o administrativa deberá sujetarse al principio de igualdad civil y a los derechos y deberes de solidaridad humana, y asegurar el goce de la libertad personal, el trabajo, la propiedad y la honra. Nadie puede ser privado de esos derechos, sino mediante sentencia fundada en ley, aplicada por juez competente.`, currentText: `Toda norma legal o administrativa deberá sujetarse al principio de igualdad civil y a los derechos y deberes de solidaridad humana, y asegurar el goce de la libertad personal, el trabajo, la propiedad y la honra. Nadie puede ser privado de esos derechos, sino mediante sentencia fundada en ley, aplicada por juez competente.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 8, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-10', lawId: 'const-santa-cruz', number: '10', title: '', originalText: `Queda prohibida toda forma de explotación de las personas, que atente contra la dignidad humana.`, currentText: `Queda prohibida toda forma de explotación de las personas, que atente contra la dignidad humana.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 9, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-11', lawId: 'const-santa-cruz', number: '11', title: '', originalText: `No podrán dictarse leyes ni otras medidas que restrinjan la libertad de palabra hablada o escrita. No existirá censura previa ni se exigirán garantías pecuniarias. La libertad de prensa comprenderá la de buscar, recibir y difundir las ideas e informaciones por todos los medios orales y escritos o por apartos visuales o auditivos.`, currentText: `No podrán dictarse leyes ni otras medidas que restrinjan la libertad de palabra hablada o escrita. No existirá censura previa ni se exigirán garantías pecuniarias. La libertad de prensa comprenderá la de buscar, recibir y difundir las ideas e informaciones por todos los medios orales y escritos o por apartos visuales o auditivos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 10, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-12', lawId: 'const-santa-cruz', number: '12', title: '', originalText: `Una ley establecerá penas para los delitos de prensa cometidos por los medios mencionados en el artículo anterior y reprimirá las publicaciones que afecten la moral y las buenas costumbres. Tales delitos nunca se considerarán flagrantes. El proceso tendrá lugar en los Tribunales Ordinarios y durante su sustanciación no podrán entorpecerse las publicaciones ni secuestrarse las imprentas, útiles, materiales, herramientas o maquinaria usadas para la impresión o difusión.`, currentText: `Una ley establecerá penas para los delitos de prensa cometidos por los medios mencionados en el artículo anterior y reprimirá las publicaciones que afecten la moral y las buenas costumbres. Tales delitos nunca se considerarán flagrantes. El proceso tendrá lugar en los Tribunales Ordinarios y durante su sustanciación no podrán entorpecerse las publicaciones ni secuestrarse las imprentas, útiles, materiales, herramientas o maquinaria usadas para la impresión o difusión.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 11, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-13', lawId: 'const-santa-cruz', number: '13', title: '', originalText: `Todo habitante tendrá derecho a replicar o rectificar las informaciones o referencias suceptibles de afectarlo personalmente, en forma gratuita y por el mismo medio en que se haya hecho tal referencia o información. Una ley reglamentará el ejercicio de este derecho.`, currentText: `Todo habitante tendrá derecho a replicar o rectificar las informaciones o referencias suceptibles de afectarlo personalmente, en forma gratuita y por el mismo medio en que se haya hecho tal referencia o información. Una ley reglamentará el ejercicio de este derecho.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 12, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-14', lawId: 'const-santa-cruz', number: '14', title: '', originalText: `Una Ley determinará la forma en que el Gobierno concurrirá materialmente a la difusión por la prensa de las ideas de los Partidos Políticos.`, currentText: `Una Ley determinará la forma en que el Gobierno concurrirá materialmente a la difusión por la prensa de las ideas de los Partidos Políticos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 13, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-15', lawId: 'const-santa-cruz', number: '15', title: '', originalText: `Los jueces prestarán amparo a todo derecho reconocido por la Constitución Nacional y ésta, y si no hubiera reglamentación o procedimiento legal, arbitrará a ese efecto trámites breves.`, currentText: `Los jueces prestarán amparo a todo derecho reconocido por la Constitución Nacional y ésta, y si no hubiera reglamentación o procedimiento legal, arbitrará a ese efecto trámites breves.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 14, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-16', lawId: 'const-santa-cruz', number: '16', title: '', originalText: `Toda persona que sufriere una prisión arbitraria, podrá ocurrir por sí o por terceros al juez más inmediato, para que haciéndole comparecer a su presencia se informe de modo que ha sido preso y resultando no haberse llenado los requisitos legales, lo mande poner inmediatamente en libertad o lo someta, en su caso, a juez competente.`, currentText: `Toda persona que sufriere una prisión arbitraria, podrá ocurrir por sí o por terceros al juez más inmediato, para que haciéndole comparecer a su presencia se informe de modo que ha sido preso y resultando no haberse llenado los requisitos legales, lo mande poner inmediatamente en libertad o lo someta, en su caso, a juez competente.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 15, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-17', lawId: 'const-santa-cruz', number: '17', title: '', originalText: `Toda ley, decreto u orden contrarios a los principios, derechos o garantías que esta Constitución consagra, no podrán ser aplicados por los jueces. Todo individuo que por tales leyes, derechos u órdenes sea lesionado en sus derechos, tiene acción civil para pedir indemnización por los perjuicios que se le hayan causado, contra el empleado, funcionario o mandatario que los hubiera dictado, autorizado o ejecutado.`, currentText: `Toda ley, decreto u orden contrarios a los principios, derechos o garantías que esta Constitución consagra, no podrán ser aplicados por los jueces. Todo individuo que por tales leyes, derechos u órdenes sea lesionado en sus derechos, tiene acción civil para pedir indemnización por los perjuicios que se le hayan causado, contra el empleado, funcionario o mandatario que los hubiera dictado, autorizado o ejecutado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 16, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-18', lawId: 'const-santa-cruz', number: '18', title: '', originalText: `Siempre que una ley u ordenanza imponga a un funcionario o corporación pública de carácter administrativo un deber expresamente determinado, todo aquel en cuyo interés deba ejecutarse el acto, o sufriere perjuicio material, moral o político, por falta de cumplimiento del deber, puede demandar ante los Tribunales su ejecución inmediata y el Tribunal, previa comprobación sumaria de la obligación legal y del derecho del reclamante, dirigirá al funcionario o corporación un mandamiento de ejecución.`, currentText: `Siempre que una ley u ordenanza imponga a un funcionario o corporación pública de carácter administrativo un deber expresamente determinado, todo aquel en cuyo interés deba ejecutarse el acto, o sufriere perjuicio material, moral o político, por falta de cumplimiento del deber, puede demandar ante los Tribunales su ejecución inmediata y el Tribunal, previa comprobación sumaria de la obligación legal y del derecho del reclamante, dirigirá al funcionario o corporación un mandamiento de ejecución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 17, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-19', lawId: 'const-santa-cruz', number: '19', title: '', originalText: `El proceso penal será público y oral. La manifestación de culpabilidad prestada por un detenido ante la policía no tendrá el carácter probatorio de la confesión.`, currentText: `El proceso penal será público y oral. La manifestación de culpabilidad prestada por un detenido ante la policía no tendrá el carácter probatorio de la confesión.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 18, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-20', lawId: 'const-santa-cruz', number: '20', title: '', originalText: `Si las leyes penales de la Nación establecieran la pena de muerte para delitos comunes, no podrá imponerse en el territorio de la provincia sino por unanimidad de votos de los miembros del Tribunal Superior de Justicia.`, currentText: `Si las leyes penales de la Nación establecieran la pena de muerte para delitos comunes, no podrá imponerse en el territorio de la provincia sino por unanimidad de votos de los miembros del Tribunal Superior de Justicia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 19, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-21', lawId: 'const-santa-cruz', number: '21', title: '', originalText: `Nadie puede ser perseguido más de una vez por un mismo delito, ni bajo pretexto alguno podrán suscitarse de nuevo pleitos terminados con sentencia ejecutoria.`, currentText: `Nadie puede ser perseguido más de una vez por un mismo delito, ni bajo pretexto alguno podrán suscitarse de nuevo pleitos terminados con sentencia ejecutoria.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 20, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-22', lawId: 'const-santa-cruz', number: '22', title: '', originalText: `En causa criminal nadie será obligado a declarar contra sí mismo, ni contra sus parientes consanguíneos hasta el cuarto grado o afines hasta el segundo.`, currentText: `En causa criminal nadie será obligado a declarar contra sí mismo, ni contra sus parientes consanguíneos hasta el cuarto grado o afines hasta el segundo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 21, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-23', lawId: 'const-santa-cruz', number: '23', title: '', originalText: `Todo aprehendido deberá ser notificado dentro de las veinticuatro horas de la causa de su detención. Dentro del mismo plazo deberá darse aviso al Juez competente, poniéndose al detenido a su disposición. La incomunicación absoluta no podrá durar más de tres días.`, currentText: `Todo aprehendido deberá ser notificado dentro de las veinticuatro horas de la causa de su detención. Dentro del mismo plazo deberá darse aviso al Juez competente, poniéndose al detenido a su disposición. La incomunicación absoluta no podrá durar más de tres días.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 22, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-24', lawId: 'const-santa-cruz', number: '24', title: '', originalText: `Son reputados inocentes todos aquellos que por sentencia firme no hayan sido declarados culpables.`, currentText: `Son reputados inocentes todos aquellos que por sentencia firme no hayan sido declarados culpables.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 23, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-25', lawId: 'const-santa-cruz', number: '25', title: '', originalText: `Podrá ser excarcelada o eximida de prisión la persona que diera caución juratoria, o fianza suficiente en los casos y condiciones que determine la ley atendiendo el delito cometido y sus circunstancias.`, currentText: `Podrá ser excarcelada o eximida de prisión la persona que diera caución juratoria, o fianza suficiente en los casos y condiciones que determine la ley atendiendo el delito cometido y sus circunstancias.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 24, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-26', lawId: 'const-santa-cruz', number: '26', title: '', originalText: `Nadie podrá ser privado de libertad ni allanado su domicilio sin orden escrita del Juez competente, salvo en caso de flagrante delito.`, currentText: `Nadie podrá ser privado de libertad ni allanado su domicilio sin orden escrita del Juez competente, salvo en caso de flagrante delito.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 25, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-27', lawId: 'const-santa-cruz', number: '27', title: '', originalText: `Todo alcalde o guardián de presos, al recibir alguno, deberá exigir y conservar en su poder la orden de que habla el artículo anterior, so pena de hacerse responsable de una prisión indebida. Artículos 28.- Las cárceles de la Provincia serán establecimientos de readaptación social y no podrá tomarse medida alguna que, a pretexto de precaución conduzca a mortificar los presos más allá de lo que su seguridad exija.`, currentText: `Todo alcalde o guardián de presos, al recibir alguno, deberá exigir y conservar en su poder la orden de que habla el artículo anterior, so pena de hacerse responsable de una prisión indebida. Artículos 28.- Las cárceles de la Provincia serán establecimientos de readaptación social y no podrá tomarse medida alguna que, a pretexto de precaución conduzca a mortificar los presos más allá de lo que su seguridad exija.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 26, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-29', lawId: 'const-santa-cruz', number: '29', title: '', originalText: `Una ley establecerá indemnización para quienes habiendo estado detenidos por más de sesenta días fueran absueltos o sobreseídos definitivamente.`, currentText: `Una ley establecerá indemnización para quienes habiendo estado detenidos por más de sesenta días fueran absueltos o sobreseídos definitivamente.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 27, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-30', lawId: 'const-santa-cruz', number: '30', title: '', originalText: `De la aplicación de torturas o vejámenes, cualquiera fuera la causa o lugar, serán responsables tanto los funcionarios que los autoricen como los empleados que los infieran, y quedarán ambos destituidos de sus cargos o empleos, sin perjuicio de las sanciones penales que correspondan.`, currentText: `De la aplicación de torturas o vejámenes, cualquiera fuera la causa o lugar, serán responsables tanto los funcionarios que los autoricen como los empleados que los infieran, y quedarán ambos destituidos de sus cargos o empleos, sin perjuicio de las sanciones penales que correspondan.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 28, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-31', lawId: 'const-santa-cruz', number: '31', title: '', originalText: `Ningún magistrado o funcionario público podrá delegar sin autorización legal sus funciones en otra persona, ni un Poder delegar en otro sus atribuciones constitucionales, siendo nulo lo que cualquiera de ellos obrase en nombre de otro, salvo los casos previstos por esta Constitución.`, currentText: `Ningún magistrado o funcionario público podrá delegar sin autorización legal sus funciones en otra persona, ni un Poder delegar en otro sus atribuciones constitucionales, siendo nulo lo que cualquiera de ellos obrase en nombre de otro, salvo los casos previstos por esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 29, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-32', lawId: 'const-santa-cruz', number: '32', title: '', originalText: `La idoneidad será la única condición para el desempeño de cargos y empleos públicos, quedando expresamente prohibido exigir para ello afiliación política alguna. Ningún empleado de la Provincia o de las Municipalidades, con más de seis meses de servicios, podrá ser separado de su cargo mientras dure su buena conducta, sus aptitudes físicas o mentales y su contracción eficiente a la misión encomendada, a excepción de aquellos para cuyo nombramiento o cesantía se hayan previsto por esta Constitución o las leyes, normas especiales. En cualquier caso en que fueran dados de baja sin reunirse los recaudos previstos en esta Constitución, podrán demandar judicialmente la reposición en el cargo o la indemnización que la ley determine.`, currentText: `La idoneidad será la única condición para el desempeño de cargos y empleos públicos, quedando expresamente prohibido exigir para ello afiliación política alguna. Ningún empleado de la Provincia o de las Municipalidades, con más de seis meses de servicios, podrá ser separado de su cargo mientras dure su buena conducta, sus aptitudes físicas o mentales y su contracción eficiente a la misión encomendada, a excepción de aquellos para cuyo nombramiento o cesantía se hayan previsto por esta Constitución o las leyes, normas especiales. En cualquier caso en que fueran dados de baja sin reunirse los recaudos previstos en esta Constitución, podrán demandar judicialmente la reposición en el cargo o la indemnización que la ley determine.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 30, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-33', lawId: 'const-santa-cruz', number: '33', title: '', originalText: `Una ley reglamentará la garantía del artículo anterior, con arreglo a lo dispuesto en el artículo sobre Tribunal disciplinario, y asegurará el sueldo y salario mínimo para los empleados públicos.`, currentText: `Una ley reglamentará la garantía del artículo anterior, con arreglo a lo dispuesto en el artículo sobre Tribunal disciplinario, y asegurará el sueldo y salario mínimo para los empleados públicos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 31, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-34', lawId: 'const-santa-cruz', number: '34', title: '', originalText: `No podrá acordarse remuneración extraordinaria a ningún empleado o funcionario de los poderes públicos, por servicios hechos o encagados en el ejercicio de sus funciones o por comisiones especiales.`, currentText: `No podrá acordarse remuneración extraordinaria a ningún empleado o funcionario de los poderes públicos, por servicios hechos o encagados en el ejercicio de sus funciones o por comisiones especiales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 32, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-35', lawId: 'const-santa-cruz', number: '35', title: '', originalText: `Todo funcionario público o empleado de la administración a quien se le imputen delitos cometidos en el desempeño de sus funciones, está obligado a acusar para vindicarse bajo pena de destitución, y gozará del beneficio del proceso gratuito.`, currentText: `Todo funcionario público o empleado de la administración a quien se le imputen delitos cometidos en el desempeño de sus funciones, está obligado a acusar para vindicarse bajo pena de destitución, y gozará del beneficio del proceso gratuito.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 33, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-36', lawId: 'const-santa-cruz', number: '36', title: '', originalText: `La Provincia y los Municipios pueden ser demandados ante los Jueces Ordinarios sin autorización de la Cámara y sin que puedan gozar en el juicio de privilegio alguno. Sus bienes y rentas no podrán ser objeto de medidas cautelares preventivas. Por Ley se reglará el modo de efectivización de las sentencias en las que hubieran sido condenados, la que deberá tender a la celeridad en el cumplimiento.`, currentText: `La Provincia y los Municipios pueden ser demandados ante los Jueces Ordinarios sin autorización de la Cámara y sin que puedan gozar en el juicio de privilegio alguno. Sus bienes y rentas no podrán ser objeto de medidas cautelares preventivas. Por Ley se reglará el modo de efectivización de las sentencias en las que hubieran sido condenados, la que deberá tender a la celeridad en el cumplimiento.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 34, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-37', lawId: 'const-santa-cruz', number: '37', title: '', originalText: `La Provincia proveerá sus gastos con los fondos del Tesoro Provincial, formado por la actividad económica que realice y servicios que preste; venta y arrendamiento de sus tierras públicas y demás bienes propios; cánones y regalías para la explotación de sus minas, yacimientos y fuentes de energía; contribuciones, impuestos, tasas y derechos que imponga y operaciones de crédito que efectúe.`, currentText: `La Provincia proveerá sus gastos con los fondos del Tesoro Provincial, formado por la actividad económica que realice y servicios que preste; venta y arrendamiento de sus tierras públicas y demás bienes propios; cánones y regalías para la explotación de sus minas, yacimientos y fuentes de energía; contribuciones, impuestos, tasas y derechos que imponga y operaciones de crédito que efectúe.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 35, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-38', lawId: 'const-santa-cruz', number: '38', title: '', originalText: `Las contribuciones se inspirarán en propósitos de justicia social y deberá procurarse que no graviten sobre los artículos de primera necesidad y el patrimonio mínimo familiar. Las autoridades provinciales denunciarán los contratos leyes que existan firmados con la Nación para la unificación de impuestos y reivindicarán la plenitud de sus derechos impositivos.`, currentText: `Las contribuciones se inspirarán en propósitos de justicia social y deberá procurarse que no graviten sobre los artículos de primera necesidad y el patrimonio mínimo familiar. Las autoridades provinciales denunciarán los contratos leyes que existan firmados con la Nación para la unificación de impuestos y reivindicarán la plenitud de sus derechos impositivos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 36, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-39', lawId: 'const-santa-cruz', number: '39', title: '', originalText: `El Poder Ejecutivo no podrá crear ni modificar impuestos, tasas o contribuciones, ni establecer clase alguna de requisición o gravamen bajo cualquier nombre y cualquiera sea su fundamento. El procedimiento para la percepción de la renta pública y de los otros recursos que forman el Tesoro Provincial y lo relativo a la aplicación y fiscalización de los mismos se fijará por ley.`, currentText: `El Poder Ejecutivo no podrá crear ni modificar impuestos, tasas o contribuciones, ni establecer clase alguna de requisición o gravamen bajo cualquier nombre y cualquiera sea su fundamento. El procedimiento para la percepción de la renta pública y de los otros recursos que forman el Tesoro Provincial y lo relativo a la aplicación y fiscalización de los mismos se fijará por ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 37, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-40', lawId: 'const-santa-cruz', number: '40', title: '', originalText: `No podrá autorizarse empréstito alguno sobre el crédito general de la Provincia, ni emisión de fondos públicos, sino por ley sancionada por los dos tercios de votos de los legisladores presentes, debiendo especificarse los recursos para su amortización y el objeto a que los fondos se destinen. Su aplicación a otro objeto queda prohibida bajo la responsabilidad de la autoridad que los invierta.`, currentText: `No podrá autorizarse empréstito alguno sobre el crédito general de la Provincia, ni emisión de fondos públicos, sino por ley sancionada por los dos tercios de votos de los legisladores presentes, debiendo especificarse los recursos para su amortización y el objeto a que los fondos se destinen. Su aplicación a otro objeto queda prohibida bajo la responsabilidad de la autoridad que los invierta.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 38, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-41', lawId: 'const-santa-cruz', number: '41', title: '', originalText: `Toda adquisición y enajenación de los bienes del Fisco o de los Municipios y demás contratos susceptibles de licitación y los actos oficiales que se relacionen con la percepción e inversión de la renta, deberán publicarse por la prensa periódicamente, del modo que la ley reglamente, bajo pena de nulidad y defraudación si la hubiere.`, currentText: `Toda adquisición y enajenación de los bienes del Fisco o de los Municipios y demás contratos susceptibles de licitación y los actos oficiales que se relacionen con la percepción e inversión de la renta, deberán publicarse por la prensa periódicamente, del modo que la ley reglamente, bajo pena de nulidad y defraudación si la hubiere.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 39, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-42', lawId: 'const-santa-cruz', number: '42', title: '', originalText: `La Cámara sancionará un Código Fiscal comprensivo de todas las leyes tributarias. Las leyes anuales de presupuesto no contendrán disposiciones que modifiquen la legislación fiscal.`, currentText: `La Cámara sancionará un Código Fiscal comprensivo de todas las leyes tributarias. Las leyes anuales de presupuesto no contendrán disposiciones que modifiquen la legislación fiscal.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 40, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-43', lawId: 'const-santa-cruz', number: '43', title: '', originalText: `La Cámara al sancionar las leyes impositivas eximirá a las instituciones que realicen obras de bien social sin espíritu de lucro, y estimulará en las empresas agropecuarias e industriales la reinversión con fines productivos`, currentText: `La Cámara al sancionar las leyes impositivas eximirá a las instituciones que realicen obras de bien social sin espíritu de lucro, y estimulará en las empresas agropecuarias e industriales la reinversión con fines productivos`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 41, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-44', lawId: 'const-santa-cruz', number: '44', title: 'Régimen Económico y Social', originalText: `Se protegerá la iniciativa privada en su realidad creadora. La Provincia, por ley especial, podrá intervenir en las actividades económicas para promover el bienestar económico y social, el aumento de la población y la estabilidad de la misma.`, currentText: `Se protegerá la iniciativa privada en su realidad creadora. La Provincia, por ley especial, podrá intervenir en las actividades económicas para promover el bienestar económico y social, el aumento de la población y la estabilidad de la misma.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 42, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-45', lawId: 'const-santa-cruz', number: '45', title: '', originalText: `Será prevenido y reprimido todo abuso del poder económico asi como toda actividad que obstaculice el desarrollo de la economía o tienda a dominar los mercados, eliminar la competencia o aumentar arbitrariamente los beneficios.`, currentText: `Será prevenido y reprimido todo abuso del poder económico asi como toda actividad que obstaculice el desarrollo de la economía o tienda a dominar los mercados, eliminar la competencia o aumentar arbitrariamente los beneficios.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 43, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-46', lawId: 'const-santa-cruz', number: '46', title: '', originalText: `El Gobierno de la Provincia y las Municipalidades, ambos en sus respectivas jurisdicciones crearán por leyes u ordenanzas especiales comisiones asesoras permanentes, integradas por representantes oficiales, de los consumidores, de los sectores de trabajo, la producción y el comercio, en igualdad de representación, a fin colaborar en el cumplimiento del artículo anterior y asesorar a las autoridades en la sanción de las leyes que afecten a la economía de la colectividad.`, currentText: `El Gobierno de la Provincia y las Municipalidades, ambos en sus respectivas jurisdicciones crearán por leyes u ordenanzas especiales comisiones asesoras permanentes, integradas por representantes oficiales, de los consumidores, de los sectores de trabajo, la producción y el comercio, en igualdad de representación, a fin colaborar en el cumplimiento del artículo anterior y asesorar a las autoridades en la sanción de las leyes que afecten a la economía de la colectividad.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 44, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-47', lawId: 'const-santa-cruz', number: '47', title: '', originalText: `La Provincia podrá concurrir con otras a la formación de empresas económicas interprovinciales para el aprovechamiento total de los recursos comunes sin ingerencia del Gobierno Nacional.`, currentText: `La Provincia podrá concurrir con otras a la formación de empresas económicas interprovinciales para el aprovechamiento total de los recursos comunes sin ingerencia del Gobierno Nacional.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 45, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-48', lawId: 'const-santa-cruz', number: '48', title: '', originalText: `La Provincia tenderá mendiante legislación adecuada al progreso y bienestar económico de la colectividad. Fomentará la producción de las diversas industrias madres y las transformadoras de la producción rural y todas aquellas que tiendan a aumentar el potencial económico de la Provincia, mediante la concesión de beneficios que sean compatibles con esta Constitución.`, currentText: `La Provincia tenderá mendiante legislación adecuada al progreso y bienestar económico de la colectividad. Fomentará la producción de las diversas industrias madres y las transformadoras de la producción rural y todas aquellas que tiendan a aumentar el potencial económico de la Provincia, mediante la concesión de beneficios que sean compatibles con esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 46, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-49', lawId: 'const-santa-cruz', number: '49', title: '', originalText: `La Provincia promoverá la inmigració, la construcción de medios de comunicación y de transporte y de su red caminera. Estimulará la inversión de capitales privados y en especial de los ahorros populares en las entidades económico financieras y el establecimiento de industrias.`, currentText: `La Provincia promoverá la inmigració, la construcción de medios de comunicación y de transporte y de su red caminera. Estimulará la inversión de capitales privados y en especial de los ahorros populares en las entidades económico financieras y el establecimiento de industrias.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 47, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-50', lawId: 'const-santa-cruz', number: '50', title: '', originalText: `La Provincia deberá fomentar el cooperativismo, mediante el tratamiento especial a las organizaciones de ese carácter.`, currentText: `La Provincia deberá fomentar el cooperativismo, mediante el tratamiento especial a las organizaciones de ese carácter.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 48, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-51', lawId: 'const-santa-cruz', number: '51', title: '', originalText: `El Banco de la Provincia será agente finaciero del Estado La Provincia y los Municipios serán prestatarios de sus servicios sin preferencias ni privilegios. El Gobierno no podra disponer de suma alguna del capital que se le fije. La Institución fomentará las actividades productivas, la economía regional, custodiará y promoverá el ahorro provincial y las inversiones en la Provincia. Se conformará un Directorio asegurando una efectiva participación de los sectores económicos, políticos y sociales de la Provincia.`, currentText: `El Banco de la Provincia será agente finaciero del Estado La Provincia y los Municipios serán prestatarios de sus servicios sin preferencias ni privilegios. El Gobierno no podra disponer de suma alguna del capital que se le fije. La Institución fomentará las actividades productivas, la economía regional, custodiará y promoverá el ahorro provincial y las inversiones en la Provincia. Se conformará un Directorio asegurando una efectiva participación de los sectores económicos, políticos y sociales de la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 49, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-52', lawId: 'const-santa-cruz', number: '52', title: '', originalText: `La Provincia tiene el dominio originario de los recursos naturales, renovables o no, existentes en su territorio, comprendiendo el suelo, el subsuelo, el mar adyacente a sus costas, su lecho, la plataforma continental y el espacio aéreo y de las sustancias minerales y fósiles; y lo ejercita con las particularidades que establece para cada uno, sin perjuicio de las facultades delegadas. Seran considerados en especial del dominio originario provincial: los yacimientos hidrocarburíferos, los recursos ictícolas y las fuentes de energía. Los recursos naturales y las fuentes de energía podrán ser explotados por empresas públicas, mixtas o privadas. El Estado ejercerá el poder de policía de conformidad a las normas que en su consecuencia se dicten.`, currentText: `La Provincia tiene el dominio originario de los recursos naturales, renovables o no, existentes en su territorio, comprendiendo el suelo, el subsuelo, el mar adyacente a sus costas, su lecho, la plataforma continental y el espacio aéreo y de las sustancias minerales y fósiles; y lo ejercita con las particularidades que establece para cada uno, sin perjuicio de las facultades delegadas. Seran considerados en especial del dominio originario provincial: los yacimientos hidrocarburíferos, los recursos ictícolas y las fuentes de energía. Los recursos naturales y las fuentes de energía podrán ser explotados por empresas públicas, mixtas o privadas. El Estado ejercerá el poder de policía de conformidad a las normas que en su consecuencia se dicten.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 50, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-53', lawId: 'const-santa-cruz', number: '53', title: '', originalText: `Los servicios públicos podrán ser prestados por el Estado o por empresas privadas, pero la Provincia los tomará exclusivamente a su cargo, si el interés público así lo requiere.`, currentText: `Los servicios públicos podrán ser prestados por el Estado o por empresas privadas, pero la Provincia los tomará exclusivamente a su cargo, si el interés público así lo requiere.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 51, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-54', lawId: 'const-santa-cruz', number: '54', title: '', originalText: `El bien de familia y los elementos necesarios para el trabajo manual o intelectual serán inembargables.`, currentText: `El bien de familia y los elementos necesarios para el trabajo manual o intelectual serán inembargables.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 52, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-55', lawId: 'const-santa-cruz', number: '55', title: '', originalText: `La Provincia establecerá un régimen de seguridad social que comprenda toda la población durante el transcurso de la vida humana, contemplando las consecuencias económicas y sociales de la desocupación, nacimiento, maternidad, enfermedad, desamparo, invalidez y muerte; fomentará las instituciones de solidaridad social, los establecimientos de ahorro y fomentará y contribuirá a la construcción de viviendas higiénicas.`, currentText: `La Provincia establecerá un régimen de seguridad social que comprenda toda la población durante el transcurso de la vida humana, contemplando las consecuencias económicas y sociales de la desocupación, nacimiento, maternidad, enfermedad, desamparo, invalidez y muerte; fomentará las instituciones de solidaridad social, los establecimientos de ahorro y fomentará y contribuirá a la construcción de viviendas higiénicas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 53, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-56', lawId: 'const-santa-cruz', number: '56', title: '', originalText: `La Provincia protegerá la institución familiar mediante una legislación que asegure la constitución y estabilidad de su patrimonio. En ningún caso el impusto a la transmisión gratuita de bienes de padres a hijos, afectará el bien de familia y el sustento y educación de los hijos.`, currentText: `La Provincia protegerá la institución familiar mediante una legislación que asegure la constitución y estabilidad de su patrimonio. En ningún caso el impusto a la transmisión gratuita de bienes de padres a hijos, afectará el bien de familia y el sustento y educación de los hijos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 54, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-57', lawId: 'const-santa-cruz', number: '57', title: '', originalText: `La Provincia velará por la higiene y salud pública. A tal fin se organizará un régimen sanitario preventivo y asistencial, creando centros de salud en los lugares y con los medios necesarios. La aplicación de dicho régimen estará a cargo de un Consejo Sanitario Provincial con representación del Estado,profesionales y habitantes en general.`, currentText: `La Provincia velará por la higiene y salud pública. A tal fin se organizará un régimen sanitario preventivo y asistencial, creando centros de salud en los lugares y con los medios necesarios. La aplicación de dicho régimen estará a cargo de un Consejo Sanitario Provincial con representación del Estado,profesionales y habitantes en general.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 55, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-58', lawId: 'const-santa-cruz', number: '58', title: '', originalText: `La Provincia promoverá la creación de institutos de difusión cultural, y extremará las medidas tendientes a consolidar la paz social sobre las bases de justicia e igualdad para todos los habitantes.`, currentText: `La Provincia promoverá la creación de institutos de difusión cultural, y extremará las medidas tendientes a consolidar la paz social sobre las bases de justicia e igualdad para todos los habitantes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 56, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-59', lawId: 'const-santa-cruz', number: '59', title: '', originalText: `En los casos en que la Provincia contrate con la Nación, o sus reparticiones o entes autárquicos, la ejecución de obras dentro de la Provicncia, regirá la legislación laboral mas favorable y se preferirá la contratación de la mano de obra existente en la misma.`, currentText: `En los casos en que la Provincia contrate con la Nación, o sus reparticiones o entes autárquicos, la ejecución de obras dentro de la Provicncia, regirá la legislación laboral mas favorable y se preferirá la contratación de la mano de obra existente en la misma.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 57, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-60', lawId: 'const-santa-cruz', number: '60', title: '', originalText: `La legislación asegurará la efectividad del salario familiar y el principio de que a igual trabajo corresponde idéntica remuneración.`, currentText: `La legislación asegurará la efectividad del salario familiar y el principio de que a igual trabajo corresponde idéntica remuneración.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 58, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-61', lawId: 'const-santa-cruz', number: '61', title: '', originalText: `La Provincia reconoce el derecho a la libre constitución y actuación de las asociaciones profesionales, el derecho de los trabajadores a afiliarse o no a un sindicato, y a fundar una o varias organizaciones sindicales. Igual derecho se le reconoce a los patrones con respecto a sus organizaciones gremiales.`, currentText: `La Provincia reconoce el derecho a la libre constitución y actuación de las asociaciones profesionales, el derecho de los trabajadores a afiliarse o no a un sindicato, y a fundar una o varias organizaciones sindicales. Igual derecho se le reconoce a los patrones con respecto a sus organizaciones gremiales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 59, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-62', lawId: 'const-santa-cruz', number: '62', title: '', originalText: `La Provincia reconoce y respeta el derecho de huelga, no pudiendo tomarse contra los participantes en ella ninguna medida de fuerza mientras la misma no ponga en peligro evidente la seguridad de la población. Los Jueces garantizarán el amparo a este derecho.`, currentText: `La Provincia reconoce y respeta el derecho de huelga, no pudiendo tomarse contra los participantes en ella ninguna medida de fuerza mientras la misma no ponga en peligro evidente la seguridad de la población. Los Jueces garantizarán el amparo a este derecho.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 60, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-63', lawId: 'const-santa-cruz', number: '63', title: '', originalText: `El convenio colectivo, realizado libremente por las partes interesadas, regirá el régimen de las condiciones de trabajo, no pudiendo la Provincia intervenir sino por intermedio del Departamento Provincial del Trabajo, en caso de desacuerdo o conflicto irremediable.`, currentText: `El convenio colectivo, realizado libremente por las partes interesadas, regirá el régimen de las condiciones de trabajo, no pudiendo la Provincia intervenir sino por intermedio del Departamento Provincial del Trabajo, en caso de desacuerdo o conflicto irremediable.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 61, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-64', lawId: 'const-santa-cruz', number: '64', title: '', originalText: `Ningún representante o dirigente sindical podrá ser despedido, por razón emergente del ejercicio de sus funciones, ni perseguido ni encarcelado por los mismos motivos.`, currentText: `Ningún representante o dirigente sindical podrá ser despedido, por razón emergente del ejercicio de sus funciones, ni perseguido ni encarcelado por los mismos motivos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 62, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-65', lawId: 'const-santa-cruz', number: '65', title: '', originalText: `La Provincia asegurará la celeridad del trámite en juicio sobre materia laboral mediante una ley especial de procedimientos y asegurará el patrocinio letrado gratuito y la gratuidad del trámite procesal a la parte obrera.`, currentText: `La Provincia asegurará la celeridad del trámite en juicio sobre materia laboral mediante una ley especial de procedimientos y asegurará el patrocinio letrado gratuito y la gratuidad del trámite procesal a la parte obrera.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 63, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-66', lawId: 'const-santa-cruz', number: '66', title: '', originalText: `Una ley establecerá beneficios especiales para toda empresa en cuya dirección, administración y utilidades participen los técnicos, empleados u obreros.`, currentText: `Una ley establecerá beneficios especiales para toda empresa en cuya dirección, administración y utilidades participen los técnicos, empleados u obreros.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 64, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-67', lawId: 'const-santa-cruz', number: '67', title: '', originalText: `La tierra será considerada bien de trabajo y no de renta y será objeto de una explotación racional. Las leyes impositivas desalentarán la explotación indirecta y las que realicen sociedades de capital.`, currentText: `La tierra será considerada bien de trabajo y no de renta y será objeto de una explotación racional. Las leyes impositivas desalentarán la explotación indirecta y las que realicen sociedades de capital.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 65, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-68', lawId: 'const-santa-cruz', number: '68', title: '', originalText: `La tierra fiscal será adjudicada en propiedad irrevocable, teniendo en cuenta que cada predio debe constiuir una unidad de producción. Se entenderá por unidad de producción todo predio que por su superficie y demás condiciones de explotación tenga una capacidad productiva que permita al propietario y su familia llevar una vida digna, atender sus necesidades materiales, morales y culturales, y que facilite la evolución favorable de la empresa.`, currentText: `La tierra fiscal será adjudicada en propiedad irrevocable, teniendo en cuenta que cada predio debe constiuir una unidad de producción. Se entenderá por unidad de producción todo predio que por su superficie y demás condiciones de explotación tenga una capacidad productiva que permita al propietario y su familia llevar una vida digna, atender sus necesidades materiales, morales y culturales, y que facilite la evolución favorable de la empresa.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 66, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-69', lawId: 'const-santa-cruz', number: '69', title: '', originalText: `Se declaran inembargables el predio y las mejoras de las unidades de producción.`, currentText: `Se declaran inembargables el predio y las mejoras de las unidades de producción.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 67, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-70', lawId: 'const-santa-cruz', number: '70', title: '', originalText: `Se tenderá a la eliminación de los latifundios, mediante impuestos territoriales progresivos, impuestos al mayor valor social en las transferencias, y expropiaciones directas. Se considerará latifundio la gran extensión de tierra, en producción o no, que atente contra el progreso y bienestar de la coletividad.`, currentText: `Se tenderá a la eliminación de los latifundios, mediante impuestos territoriales progresivos, impuestos al mayor valor social en las transferencias, y expropiaciones directas. Se considerará latifundio la gran extensión de tierra, en producción o no, que atente contra el progreso y bienestar de la coletividad.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 68, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-71', lawId: 'const-santa-cruz', number: '71', title: '', originalText: `La Cámara elaborará un plan destinado a poblar la campaña, racionalizar las explotaciones rurales, estabilizar la población rural sobre la base de la propiedad, y llevar mayor bienestar a los trabajadores del campo. A tal efecto se creará un Consejo Agrario Provincial que tendrá a su cargo la tarea de distribución y redistribución de la tierra, fomento del crédito agrario, asesoramiento técnico, selección pública de aspirantes a adjudicciones y todas aquellas funciones que la ley determine.`, currentText: `La Cámara elaborará un plan destinado a poblar la campaña, racionalizar las explotaciones rurales, estabilizar la población rural sobre la base de la propiedad, y llevar mayor bienestar a los trabajadores del campo. A tal efecto se creará un Consejo Agrario Provincial que tendrá a su cargo la tarea de distribución y redistribución de la tierra, fomento del crédito agrario, asesoramiento técnico, selección pública de aspirantes a adjudicciones y todas aquellas funciones que la ley determine.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 69, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-72', lawId: 'const-santa-cruz', number: '72', title: '', originalText: `El Consejo Agrario Provincial será autárquico e integrado por productores, trabajadores del campo, y profesionales especializados que designe el Gobierno Provincial. Se tomarán todos los recaudos necesarios para dar estabilidad a sus miembros y evitar que queden supeditados a las contingencias políticas.`, currentText: `El Consejo Agrario Provincial será autárquico e integrado por productores, trabajadores del campo, y profesionales especializados que designe el Gobierno Provincial. Se tomarán todos los recaudos necesarios para dar estabilidad a sus miembros y evitar que queden supeditados a las contingencias políticas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 70, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-73', lawId: 'const-santa-cruz', number: '73', title: '', originalText: `Toda persona tendrá derecho a disfrutar de un ambiente adecuado para su desarrollo personal. El Estado y los particulares estarán obligados al cuidado y a la preservación del medio ambiente, así como a una explotación racional de los recursos naturales, para que las actividades productivas satisfagan las necesidades presentes sin comprometer las de las generaciones futuras. Por ley se reglarán las acciones tendientes a impedir toda agresión contra el medio ambiente y se crearán los organismos a los que se encomendará la aplicación de estos preceptos. El daño ambiental generará prioritariamente la obligación de recomponer según lo establezca la ley y se asegurarán estudios del impacto ambiental en los emprendimientos que se realicen. Se prohibe el ingreso al territorio provincial de residuos actual o potencialmente peligrosos y de los radiactivos o los de cualquier otra índole o naturaleza comprobadamente tóxicos, peligrosos o susceptibles de serlo en el futuro.`, currentText: `Toda persona tendrá derecho a disfrutar de un ambiente adecuado para su desarrollo personal. El Estado y los particulares estarán obligados al cuidado y a la preservación del medio ambiente, así como a una explotación racional de los recursos naturales, para que las actividades productivas satisfagan las necesidades presentes sin comprometer las de las generaciones futuras. Por ley se reglarán las acciones tendientes a impedir toda agresión contra el medio ambiente y se crearán los organismos a los que se encomendará la aplicación de estos preceptos. El daño ambiental generará prioritariamente la obligación de recomponer según lo establezca la ley y se asegurarán estudios del impacto ambiental en los emprendimientos que se realicen. Se prohibe el ingreso al territorio provincial de residuos actual o potencialmente peligrosos y de los radiactivos o los de cualquier otra índole o naturaleza comprobadamente tóxicos, peligrosos o susceptibles de serlo en el futuro.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 71, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-74', lawId: 'const-santa-cruz', number: '74', title: '', originalText: `La ley agraria tenderá a la defensa de los suelos fomentando la forestación, reforestación, riego, defensa de las especies vegetales y velará por la explotación racional de los mismos.`, currentText: `La ley agraria tenderá a la defensa de los suelos fomentando la forestación, reforestación, riego, defensa de las especies vegetales y velará por la explotación racional de los mismos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 72, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-75', lawId: 'const-santa-cruz', number: '75', title: '', originalText: `Se organizará un régimen de crédito agrario que contemple las necesidades del poblador y su familia. El régimen de pagos y amortizaciones contemplará el ciclo agrobiológico y el rendimiento de la explotación.`, currentText: `Se organizará un régimen de crédito agrario que contemple las necesidades del poblador y su familia. El régimen de pagos y amortizaciones contemplará el ciclo agrobiológico y el rendimiento de la explotación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 73, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-76', lawId: 'const-santa-cruz', number: '76', title: '', originalText: `No podrán ser concesionario ni adquirentes de tierras fiscales quienes no tengan domicilio real en la Provincia`, currentText: `No podrán ser concesionario ni adquirentes de tierras fiscales quienes no tengan domicilio real en la Provincia`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 74, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-77', lawId: 'const-santa-cruz', number: '77', title: 'Régimen Electoral', originalText: `El sufragio es una función política que todo ciudadano argentino domiciliado en la Provincia, tiene el deber de desempeñar con arreglo a esta Constitución y a la ley.`, currentText: `El sufragio es una función política que todo ciudadano argentino domiciliado en la Provincia, tiene el deber de desempeñar con arreglo a esta Constitución y a la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 75, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-78', lawId: 'const-santa-cruz', number: '78', title: '', originalText: `Se sancionará una ley electoral uniforme para toda la Provincia, de acuerdo a las siguientes bases: 1) Las eleciones se realizarán conforme al padrón electoral de la Nación vigente a la época de la elección respectiva. 2) Las elecciones podrán ser simultáneas con las nacionales, bajo las mismas autoridades de comicio y escrutinio. 3) Voto secreto y obligatorio. 4) Los ciudadanos votarán en el colegio electoral de su domicilio. 5) Fiscalización por los partidos políticos. 6) Escrutinio público e inmediato, practicado en el mismo lugar del comicio. 7) Tribunal Electoral Permanente formado por los miembros del Tribunal Superior de Justicia. 8) Libertad electoral garantizada por severas medidas gubernativas y sanciones contra quienes las conculquen. 9) Representación de la minoría.`, currentText: `Se sancionará una ley electoral uniforme para toda la Provincia, de acuerdo a las siguientes bases: 1) Las eleciones se realizarán conforme al padrón electoral de la Nación vigente a la época de la elección respectiva. 2) Las elecciones podrán ser simultáneas con las nacionales, bajo las mismas autoridades de comicio y escrutinio. 3) Voto secreto y obligatorio. 4) Los ciudadanos votarán en el colegio electoral de su domicilio. 5) Fiscalización por los partidos políticos. 6) Escrutinio público e inmediato, practicado en el mismo lugar del comicio. 7) Tribunal Electoral Permanente formado por los miembros del Tribunal Superior de Justicia. 8) Libertad electoral garantizada por severas medidas gubernativas y sanciones contra quienes las conculquen. 9) Representación de la minoría.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 76, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-79', lawId: 'const-santa-cruz', number: '79', title: '', originalText: `Una ley establecerá el régimen para los Partidos Políticos que actúen en la Provincia, y sus bases serán las siguientes: 1) Obligación para los Partidos Políticos de sancionar una plataforma electoral y una carta orgánica conforme al régimen legal, y que establezca: a) Publicidad del padrón de afiliados. b) Publicidad del origen y destino de sus fondos. 2) Garantía de los comicios internos para candidatos a cargos electivos, provinciales y municipales por el Tribunal Electoral Permanente, conforme a los procedimientos que determinen las respectivas cartas orgánicas.`, currentText: `Una ley establecerá el régimen para los Partidos Políticos que actúen en la Provincia, y sus bases serán las siguientes: 1) Obligación para los Partidos Políticos de sancionar una plataforma electoral y una carta orgánica conforme al régimen legal, y que establezca: a) Publicidad del padrón de afiliados. b) Publicidad del origen y destino de sus fondos. 2) Garantía de los comicios internos para candidatos a cargos electivos, provinciales y municipales por el Tribunal Electoral Permanente, conforme a los procedimientos que determinen las respectivas cartas orgánicas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 77, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-80', lawId: 'const-santa-cruz', number: '80', title: '', originalText: `La Cámara de Diputados por la mayoría absoluta de la totalidad de sus miembros, podrá someter a voto popular directo, oblligatorio vinculante, en calidad de Consulta Popular, proyectos de ley que afecten directa o indirectamente las instituciones, derechos y garantías de raigambre constitucional nacional o provincial, para su ratificación o rechazo. La ley de convocatoria no podrá ser vetada y regirá automáticamente a partir de su ratificación. El Poder Legislativo y el Poder Ejecutivo dentro de sus respectivas competencias, podrán convocar a consulta popular no vinculante. En este caso el voto no será obligatorio. Los partidos políticos son las instituciones indispensables de la democracia, responsables de la cultura política y de la confianza que el pueblo deposita en ellos y garantes de la participación ciudadana. Se asegurará la representación de los partidos políticos en los organismos colegiados cuya naturaleza jurídica lo permita, y no tengan fijada por esta Constitución una conformación especial`, currentText: `La Cámara de Diputados por la mayoría absoluta de la totalidad de sus miembros, podrá someter a voto popular directo, oblligatorio vinculante, en calidad de Consulta Popular, proyectos de ley que afecten directa o indirectamente las instituciones, derechos y garantías de raigambre constitucional nacional o provincial, para su ratificación o rechazo. La ley de convocatoria no podrá ser vetada y regirá automáticamente a partir de su ratificación. El Poder Legislativo y el Poder Ejecutivo dentro de sus respectivas competencias, podrán convocar a consulta popular no vinculante. En este caso el voto no será obligatorio. Los partidos políticos son las instituciones indispensables de la democracia, responsables de la cultura política y de la confianza que el pueblo deposita en ellos y garantes de la participación ciudadana. Se asegurará la representación de los partidos políticos en los organismos colegiados cuya naturaleza jurídica lo permita, y no tengan fijada por esta Constitución una conformación especial`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 78, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-81', lawId: 'const-santa-cruz', number: '81', title: 'Régimen Educacional', originalText: `La enseñanza primaria será gratuita y obligatoria. La Provincia concurrirá a los esfuerzos de los particulares, para que la enseñanza en sus diversos grados este al alcance de todos sus habitantes y a tal efecto deberá: 1) Crear establecimientos públicos de enseñanza primaria secundaria y técnica. 2) Subvencional a las entidades particulares que cumplan con los programas mínimos oficiales, en proporcion al número de alumnos que eduquen, de manera que la enseñanza sea gratuita. 3) Organizar y coadyuvar a la formación de instituciones culturales, artísticas y universitarias, aun cuando fueren interprovinciales. 4) Acordar becas para las universidades e institutos técnicos superiores.`, currentText: `La enseñanza primaria será gratuita y obligatoria. La Provincia concurrirá a los esfuerzos de los particulares, para que la enseñanza en sus diversos grados este al alcance de todos sus habitantes y a tal efecto deberá: 1) Crear establecimientos públicos de enseñanza primaria secundaria y técnica. 2) Subvencional a las entidades particulares que cumplan con los programas mínimos oficiales, en proporcion al número de alumnos que eduquen, de manera que la enseñanza sea gratuita. 3) Organizar y coadyuvar a la formación de instituciones culturales, artísticas y universitarias, aun cuando fueren interprovinciales. 4) Acordar becas para las universidades e institutos técnicos superiores.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 79, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-82', lawId: 'const-santa-cruz', number: '82', title: '', originalText: `Para la confección de los programas mínimos de enseñanza, administración de las rentas escolares, dirección de los establecimientos oficiales y supervisión de los particulares, se organizará un Consejo Provincial de Educación, integrado por representantes de los padres de los alumnos, de los docentes y del Gobierno, en la proporción que establezca la ley respectiva. La designación de los integrantes del Consejo se hará con acuerdo de la Cámara.`, currentText: `Para la confección de los programas mínimos de enseñanza, administración de las rentas escolares, dirección de los establecimientos oficiales y supervisión de los particulares, se organizará un Consejo Provincial de Educación, integrado por representantes de los padres de los alumnos, de los docentes y del Gobierno, en la proporción que establezca la ley respectiva. La designación de los integrantes del Consejo se hará con acuerdo de la Cámara.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 80, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-83', lawId: 'const-santa-cruz', number: '83', title: '', originalText: `La Provincia reconocerá la más amplia libertad de enseñanza y cátedra, y aceptará como válidos los certificados de estudios que expidan los establecimientos particulares siempre que cumplan el programa mínimo de enseñanza, sus docentes tengan título habilitante, no atenten contra el bien y respeten las tradiciones argentinas.`, currentText: `La Provincia reconocerá la más amplia libertad de enseñanza y cátedra, y aceptará como válidos los certificados de estudios que expidan los establecimientos particulares siempre que cumplan el programa mínimo de enseñanza, sus docentes tengan título habilitante, no atenten contra el bien y respeten las tradiciones argentinas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 81, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-84', lawId: 'const-santa-cruz', number: '84', title: '', originalText: `Fíjase como fondo propio para el sostenimiento de la educación una suma no inferior al veinte por ciento de la renta fiscal de la Provincia, asegurándose a los docentes de todos los establecimiento idéntica remuneración de acuerdo al correspondiente escalafón`, currentText: `Fíjase como fondo propio para el sostenimiento de la educación una suma no inferior al veinte por ciento de la renta fiscal de la Provincia, asegurándose a los docentes de todos los establecimiento idéntica remuneración de acuerdo al correspondiente escalafón`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 82, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-85', lawId: 'const-santa-cruz', number: '85', title: 'Organizacion', originalText: `El Poder Legislativo será ejercido por una Cámara de Diputados compuesta de veinticuatro miembros, catorce electos a razón de uno por cada municipio y los restantes elegidos directamente por el pueblo de la Provincia en distrito único, asegurando la representación de las minorías.`, currentText: `El Poder Legislativo será ejercido por una Cámara de Diputados compuesta de veinticuatro miembros, catorce electos a razón de uno por cada municipio y los restantes elegidos directamente por el pueblo de la Provincia en distrito único, asegurando la representación de las minorías.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 83, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-86', lawId: 'const-santa-cruz', number: '86', title: '', originalText: `Para ser Diputado se requiere: 1) Haber cumplido la edad de 21 años. 2)Tener ciudadanía natural en ejercicio o legal después de diez años de obtenida. 3) Ser natural de la Provincia, o tener dos años de residencia inmediata en ella o diez años alternada.`, currentText: `Para ser Diputado se requiere: 1) Haber cumplido la edad de 21 años. 2)Tener ciudadanía natural en ejercicio o legal después de diez años de obtenida. 3) Ser natural de la Provincia, o tener dos años de residencia inmediata en ella o diez años alternada.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 84, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-87', lawId: 'const-santa-cruz', number: '87', title: '', originalText: `Los Diputados durarán cuatro años en sus mandatos y podrán ser reelectos. La Cámara se renovará íntegramente en oportunidad de la elección del Gobernador y del Vicegobernador y podrá constituírse por sí misma. Una ley establecerá el régimen de incompatibilidades en el ejercicio del cargo.`, currentText: `Los Diputados durarán cuatro años en sus mandatos y podrán ser reelectos. La Cámara se renovará íntegramente en oportunidad de la elección del Gobernador y del Vicegobernador y podrá constituírse por sí misma. Una ley establecerá el régimen de incompatibilidades en el ejercicio del cargo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 85, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-88', lawId: 'const-santa-cruz', number: '88', title: '', originalText: `El Vicegobernador es el Presidente de la Cámara pero no tendrá voto excepto en caso de empate. El Cuerpo elegirá de su seno en cada período ordinario un Vicepresidente Primero y un Vicepresidente Segundo, los que en ese orden lo suplirán en caso de ausencia.`, currentText: `El Vicegobernador es el Presidente de la Cámara pero no tendrá voto excepto en caso de empate. El Cuerpo elegirá de su seno en cada período ordinario un Vicepresidente Primero y un Vicepresidente Segundo, los que en ese orden lo suplirán en caso de ausencia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 86, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-89', lawId: 'const-santa-cruz', number: '89', title: '', originalText: `En caso de producirse una vacante se incorporará el suplente que corresponda de acuerdo a lo que establezca la ley.`, currentText: `En caso de producirse una vacante se incorporará el suplente que corresponda de acuerdo a lo que establezca la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 87, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-90', lawId: 'const-santa-cruz', number: '90', title: '', originalText: `La Camara se reunirá automáticamente todos los años desde el primero de marzo hasta el treinta de noviembre, en sesiones ordinarias, pudiendo ser éstas prorrogadas por simple mayoría hasta el veinte de diciembre. Podrá ser convocada por el Poder Ejecutivo a sesiones extraordinarias cuando así lo requiera el interés general y deberá ser convocada por su Presidente a pedido de una tercera parte de los diputados.`, currentText: `La Camara se reunirá automáticamente todos los años desde el primero de marzo hasta el treinta de noviembre, en sesiones ordinarias, pudiendo ser éstas prorrogadas por simple mayoría hasta el veinte de diciembre. Podrá ser convocada por el Poder Ejecutivo a sesiones extraordinarias cuando así lo requiera el interés general y deberá ser convocada por su Presidente a pedido de una tercera parte de los diputados.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 88, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-91', lawId: 'const-santa-cruz', number: '91', title: '', originalText: `En caso de comvocatoria extraodinaria no podrá ocuparse sino de los asuntos para los cuales se convocaron extraordinariamente las sesiones.`, currentText: `En caso de comvocatoria extraodinaria no podrá ocuparse sino de los asuntos para los cuales se convocaron extraordinariamente las sesiones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 89, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-92', lawId: 'const-santa-cruz', number: '92', title: '', originalText: `La Cámara es Juez de las elecciones, derechos y títulos de sus miembros en cuanto a su validez. En este caso no podrá reconsiderar sus resoluciones.`, currentText: `La Cámara es Juez de las elecciones, derechos y títulos de sus miembros en cuanto a su validez. En este caso no podrá reconsiderar sus resoluciones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 90, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-93', lawId: 'const-santa-cruz', number: '93', title: '', originalText: `La Cámara no podrá entrar en sesión sin la mitad mas uno de sus miembros, pero un número menor podrá compeler a los ausentes a que concurran a la sesión, en los términos que la Cámara establezca. Las sesiones serán públicas salvo expresa resolución en contrario y sus decisiones se tomarán por simple mayoría de los miembros presentes excepto en los casos en que esta Constitución requiera una mayoría especial.`, currentText: `La Cámara no podrá entrar en sesión sin la mitad mas uno de sus miembros, pero un número menor podrá compeler a los ausentes a que concurran a la sesión, en los términos que la Cámara establezca. Las sesiones serán públicas salvo expresa resolución en contrario y sus decisiones se tomarán por simple mayoría de los miembros presentes excepto en los casos en que esta Constitución requiera una mayoría especial.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 91, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-94', lawId: 'const-santa-cruz', number: '94', title: '', originalText: `La minoría, en caso de renovación o por cualquier otra causa, bastará para juzgar los títulos de los nuevamente electos, siempre que se halle en mayoría absoluta con respecto a sí misma, y sólo hasta poderse constituir en quórum legal.`, currentText: `La minoría, en caso de renovación o por cualquier otra causa, bastará para juzgar los títulos de los nuevamente electos, siempre que se halle en mayoría absoluta con respecto a sí misma, y sólo hasta poderse constituir en quórum legal.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 92, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-95', lawId: 'const-santa-cruz', number: '95', title: '', originalText: `Los Diputados prestarán en el acto de su incorporación, juramento de desempeñar debidamente su cargo y obrar en todo de acuerdo con esta Constitución y la de la Nación Argentina.`, currentText: `Los Diputados prestarán en el acto de su incorporación, juramento de desempeñar debidamente su cargo y obrar en todo de acuerdo con esta Constitución y la de la Nación Argentina.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 93, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-96', lawId: 'const-santa-cruz', number: '96', title: '', originalText: `Ningún Diputado podrá ser arrestado desde el día de su elección hasta el de su cese, salvo el caso de flagrante delito no excarcelable, en cuyo caso el Juez de la causa deberá informar a la Cámara con remisión de las actuaciones dentro de los cinco días, debiendo ésta en igual término resolver si allana los fueros del procesado. Si resolviere lo contrario o no se expidiere en término, este recuperará su libertad.`, currentText: `Ningún Diputado podrá ser arrestado desde el día de su elección hasta el de su cese, salvo el caso de flagrante delito no excarcelable, en cuyo caso el Juez de la causa deberá informar a la Cámara con remisión de las actuaciones dentro de los cinco días, debiendo ésta en igual término resolver si allana los fueros del procesado. Si resolviere lo contrario o no se expidiere en término, este recuperará su libertad.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 94, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-97', lawId: 'const-santa-cruz', number: '97', title: '', originalText: `Cuando se forme querella por escrito contra un miembro de la Cámara ante la justicia, aquella recibirá el sumario enviado por el Juez y examinándolo en juicio público, podrá, con dos tercios de votos de los presentes, allanar el fuero del acusado, quedando el mismo a disposición de la justicia para su juzgamiento. La absolución o sobreseimiento definitivo importará su reincorporación automática al Cuerpo sin requerir resolución alguna de éste.`, currentText: `Cuando se forme querella por escrito contra un miembro de la Cámara ante la justicia, aquella recibirá el sumario enviado por el Juez y examinándolo en juicio público, podrá, con dos tercios de votos de los presentes, allanar el fuero del acusado, quedando el mismo a disposición de la justicia para su juzgamiento. La absolución o sobreseimiento definitivo importará su reincorporación automática al Cuerpo sin requerir resolución alguna de éste.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 95, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-98', lawId: 'const-santa-cruz', number: '98', title: '', originalText: `Los Diputados no podrán ser acusados, interrogados judicialmente, ni molestados por sus opiniones, discursos o votos que emitieran desempeñando sus mandatos. Toda ofensa dirigida contra un Diputado dentro o fuera de la Cámara por tal causa, se considerará una ofensa al Cuerpo y el autor será sancionado por el mismo.`, currentText: `Los Diputados no podrán ser acusados, interrogados judicialmente, ni molestados por sus opiniones, discursos o votos que emitieran desempeñando sus mandatos. Toda ofensa dirigida contra un Diputado dentro o fuera de la Cámara por tal causa, se considerará una ofensa al Cuerpo y el autor será sancionado por el mismo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 96, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-99', lawId: 'const-santa-cruz', number: '99', title: '', originalText: `La Cámara tendrá autoridad para corregir con arresto de hasta un mes a toda persona ajena a su seno por falta de respeto o conducta desordenada o inconveniente. Tambien podrá hacerlo con quienes ofendieran o amenazaran ofender algun Diputado en su persona o bienes por su proceder en la Cámara y a cualquiera que de alguna manera dificultase el cumplimiento de sus resoluciones, pudiendo pedir el procesamiento del responsable por los Tribunales Ordinarios.`, currentText: `La Cámara tendrá autoridad para corregir con arresto de hasta un mes a toda persona ajena a su seno por falta de respeto o conducta desordenada o inconveniente. Tambien podrá hacerlo con quienes ofendieran o amenazaran ofender algun Diputado en su persona o bienes por su proceder en la Cámara y a cualquiera que de alguna manera dificultase el cumplimiento de sus resoluciones, pudiendo pedir el procesamiento del responsable por los Tribunales Ordinarios.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 97, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-100', lawId: 'const-santa-cruz', number: '100', title: '', originalText: `La Cámara podrá hacer venir a su sala a los Ministros del Poder Ejecutivo para recibir las explicaciones o informes que juzgue convenientes, citándolos con un día de anticipación por lo menos, salvo casos de urgente gravedad, debiendo comunicarles los puntos sobre los cuales tendrán que informar.`, currentText: `La Cámara podrá hacer venir a su sala a los Ministros del Poder Ejecutivo para recibir las explicaciones o informes que juzgue convenientes, citándolos con un día de anticipación por lo menos, salvo casos de urgente gravedad, debiendo comunicarles los puntos sobre los cuales tendrán que informar.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 98, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-101', lawId: 'const-santa-cruz', number: '101', title: '', originalText: `La Cámara podrá expresar la opinión de su mayoría por medio de resoluciones o declaraciones sin fuerza de ley sobre cualquier asunto político o administrativo que afecte los intereses generales de la Provincia o de la Nación Argentina.`, currentText: `La Cámara podrá expresar la opinión de su mayoría por medio de resoluciones o declaraciones sin fuerza de ley sobre cualquier asunto político o administrativo que afecte los intereses generales de la Provincia o de la Nación Argentina.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 99, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-102', lawId: 'const-santa-cruz', number: '102', title: '', originalText: `La Cámara sancionará su propio presupuesto acordando el número de empleados que necesite y la forma en que deben proveerse los cargos. Esta ley no podrá ser vetada por el Poder Ejecutivo. Los empleados que designe se encontrarán amparados por las disposiciones a dictarse sobre el régimen de empleados públicos.`, currentText: `La Cámara sancionará su propio presupuesto acordando el número de empleados que necesite y la forma en que deben proveerse los cargos. Esta ley no podrá ser vetada por el Poder Ejecutivo. Los empleados que designe se encontrarán amparados por las disposiciones a dictarse sobre el régimen de empleados públicos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 100, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-103', lawId: 'const-santa-cruz', number: '103', title: '', originalText: `La Cámara dictará su reglamento y podrá por dos tercios de votos de los presentes en sesión, corregir a cualquiera de sus miembros por desorden de conducta en su función y aún excluirlo por indignidad o inhabilidad física o mental sobreviniente a su incorporación, en estos últimos casos con dos tercios de votos del total de sus miembros, bastando simple mayoría para aceptar las renuncias que hicieren a sus cargos`, currentText: `La Cámara dictará su reglamento y podrá por dos tercios de votos de los presentes en sesión, corregir a cualquiera de sus miembros por desorden de conducta en su función y aún excluirlo por indignidad o inhabilidad física o mental sobreviniente a su incorporación, en estos últimos casos con dos tercios de votos del total de sus miembros, bastando simple mayoría para aceptar las renuncias que hicieren a sus cargos`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 101, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-104', lawId: 'const-santa-cruz', number: '104', title: 'Atribuciones', originalText: `Corresponde al Poder Legislativo: 1) Aprobar o desechar los tratados con la Nación u otras Provincias para fines de administración de justicia, intereses económicos y en general asuntos de interés común, propendiendo a la celebración de pactos regionales en materia económica, social y de enseñanza. 2) Fijar divisiones territoriales para mejor administración, reglando la forma de descentralizar la misma., crear centros urbanos y dictar la ley orgánica de municipalidades, a las que podrá acordar subsidios cuando sus recursos no alcancen a cubrir los gastos ordinarios. 3) Legislar sobre industrias, inmigración, construcción de ferrocarriles y canales de navegación, colonización de tierras, introducción y establecimiento de nuevas industrias, importación de capitales y explotación de sus ríos. 4) Proveer lo conducente a la prosperidad de la Provincia, a la salud pública., a la asistencia, acción y previsión social., al progreso de las ciencias y las artes, la instrucción, educación y cultura., a la estabilidad de la propiedad rural y a la prestación de servicios públicos. 5) Dictar leyes orgánicas de la justicia y enseñanza conforme a esta Constitución y planes o reglamentos sobre cualquier otro objeto de interés común. 6) Establecer los impuestos y contribuciones necesarias para la formación del Tesoro Provincial de acuerdo a los principios de los artículos números 38 y 43. 7) Crear o suprimir empleos, para la administración de la Provincia, salvo los establecidos por esta Constitución, determinar sus atribuciones, reglar sus responsabilidades y la forma de hacerlas efectivas fijando su dotación. 8) Legislar sobre los servicios públicos de la provincia establecidos fuera de la jurisdicción municipal. 9) Crear reparticiones autárquicas pudiendo darles la facultad de designar su personal y administrar los fondos que se le asignen. 10) Autorizar al Poder Ejecutivo, con dos tercios de votos de los miembros presentes, para contraer empréstitos. 11) Disponer el uso y enajenación de tierras públicas conforme al régimen que establece esta Constitución. 12) Conceder primas y recompensas de estímulo a la introduccion o establecimiento de nuevas industrias. 13) Admitir y desechar la renuncia que de su cargo hicieran el Gobernador o Vicegobernador. Conceder o negar licencia a los mismos para abandonar temporariamente el territorio de la Provincia y tomarles juramento. 14) Calificar los casos de expropiación por causa de utilidad pública. 15) Disponer la construcción de obras públicas exigidas por el interés de la Provincia. 16) Autorizar la cesión de parte del territorio de la Provincia por dos tercios de votos de los presentes para objeto de utilidad pública de la Nación o de la Provincia y por unanimidad de votos cuando dicha cesión importe desmembramiento de territorio o abandono de jurisdicción. 17) Reglamentar la administración del crédito público. 18) Requerir la intervención del Gobierno Nacional en los casos previstos por la Constitución Nacional. 19) Dictar los Códigos de Procedimientos, Rural, de Faltas, Fiscal, Sanitario y Leyes sobre el Registro Civil, elecciones, Partidos Políticos, imprenta, tierras públicas, bosques y vialidad. 20) Prestar acuerdo al Poder Ejecutivo para las designaciones que por esta Constitución y por las leyes así lo requiran. 21) Conceder indultos y amnistías generales. 22) Declarar con dos tercios de votos de la totalidad de sus miembros la necesidad de la reforma parcial o total de esta Constitución. 23) Convocar a elecciones cuando el Poder Ejecutivo no lo hiciere en el término previsto por la ley electoral. 24) Dictar las leyes de asistencia social que se hicieran necesarias en beneficio de los empleados públicos. 25) Fijar anualmente, a propuesta del Poder Ejecutivo, el presupuesto general de gastos y recursos, en el que deberán figurar todos los servicios ordinarios y extraordinarios de la administración provincial, aún cuando hayan sido autorizados por leyes especiales, que se tendrán por derogadas sino se consignan en dicho presupuesto las partidas correspondientes para su ejecución. En ningún caso la Cámara podrá sancionar leyes que importen gastos sin crear los recursos necesarios cuando no existan fondos disponibles en el presupuesto. Si el Poder Ejecutivo no remitiese el proyecto de presupuesto antes del treinta y uno de agosto, la Cámara podrá iniciar su discusión tomando por base el que se encuentra en ejercicio y si no fuere sancionado ninguno se considerará prorrogado el que se halle en vigencia. 26) Designar cada año un miembro letrado, si lo hubiere, para integrar el Tribunal de Enjuiciamiento previsto por esta Constitución. 27) Dictar todas las demás leyes convenientes y necesarias para hacer efectivos los derechos y garantías y poner en ejecución los principios, poderes y autoridades establecidos por esta Constitución`, currentText: `Corresponde al Poder Legislativo: 1) Aprobar o desechar los tratados con la Nación u otras Provincias para fines de administración de justicia, intereses económicos y en general asuntos de interés común, propendiendo a la celebración de pactos regionales en materia económica, social y de enseñanza. 2) Fijar divisiones territoriales para mejor administración, reglando la forma de descentralizar la misma., crear centros urbanos y dictar la ley orgánica de municipalidades, a las que podrá acordar subsidios cuando sus recursos no alcancen a cubrir los gastos ordinarios. 3) Legislar sobre industrias, inmigración, construcción de ferrocarriles y canales de navegación, colonización de tierras, introducción y establecimiento de nuevas industrias, importación de capitales y explotación de sus ríos. 4) Proveer lo conducente a la prosperidad de la Provincia, a la salud pública., a la asistencia, acción y previsión social., al progreso de las ciencias y las artes, la instrucción, educación y cultura., a la estabilidad de la propiedad rural y a la prestación de servicios públicos. 5) Dictar leyes orgánicas de la justicia y enseñanza conforme a esta Constitución y planes o reglamentos sobre cualquier otro objeto de interés común. 6) Establecer los impuestos y contribuciones necesarias para la formación del Tesoro Provincial de acuerdo a los principios de los artículos números 38 y 43. 7) Crear o suprimir empleos, para la administración de la Provincia, salvo los establecidos por esta Constitución, determinar sus atribuciones, reglar sus responsabilidades y la forma de hacerlas efectivas fijando su dotación. 8) Legislar sobre los servicios públicos de la provincia establecidos fuera de la jurisdicción municipal. 9) Crear reparticiones autárquicas pudiendo darles la facultad de designar su personal y administrar los fondos que se le asignen. 10) Autorizar al Poder Ejecutivo, con dos tercios de votos de los miembros presentes, para contraer empréstitos. 11) Disponer el uso y enajenación de tierras públicas conforme al régimen que establece esta Constitución. 12) Conceder primas y recompensas de estímulo a la introduccion o establecimiento de nuevas industrias. 13) Admitir y desechar la renuncia que de su cargo hicieran el Gobernador o Vicegobernador. Conceder o negar licencia a los mismos para abandonar temporariamente el territorio de la Provincia y tomarles juramento. 14) Calificar los casos de expropiación por causa de utilidad pública. 15) Disponer la construcción de obras públicas exigidas por el interés de la Provincia. 16) Autorizar la cesión de parte del territorio de la Provincia por dos tercios de votos de los presentes para objeto de utilidad pública de la Nación o de la Provincia y por unanimidad de votos cuando dicha cesión importe desmembramiento de territorio o abandono de jurisdicción. 17) Reglamentar la administración del crédito público. 18) Requerir la intervención del Gobierno Nacional en los casos previstos por la Constitución Nacional. 19) Dictar los Códigos de Procedimientos, Rural, de Faltas, Fiscal, Sanitario y Leyes sobre el Registro Civil, elecciones, Partidos Políticos, imprenta, tierras públicas, bosques y vialidad. 20) Prestar acuerdo al Poder Ejecutivo para las designaciones que por esta Constitución y por las leyes así lo requiran. 21) Conceder indultos y amnistías generales. 22) Declarar con dos tercios de votos de la totalidad de sus miembros la necesidad de la reforma parcial o total de esta Constitución. 23) Convocar a elecciones cuando el Poder Ejecutivo no lo hiciere en el término previsto por la ley electoral. 24) Dictar las leyes de asistencia social que se hicieran necesarias en beneficio de los empleados públicos. 25) Fijar anualmente, a propuesta del Poder Ejecutivo, el presupuesto general de gastos y recursos, en el que deberán figurar todos los servicios ordinarios y extraordinarios de la administración provincial, aún cuando hayan sido autorizados por leyes especiales, que se tendrán por derogadas sino se consignan en dicho presupuesto las partidas correspondientes para su ejecución. En ningún caso la Cámara podrá sancionar leyes que importen gastos sin crear los recursos necesarios cuando no existan fondos disponibles en el presupuesto. Si el Poder Ejecutivo no remitiese el proyecto de presupuesto antes del treinta y uno de agosto, la Cámara podrá iniciar su discusión tomando por base el que se encuentra en ejercicio y si no fuere sancionado ninguno se considerará prorrogado el que se halle en vigencia. 26) Designar cada año un miembro letrado, si lo hubiere, para integrar el Tribunal de Enjuiciamiento previsto por esta Constitución. 27) Dictar todas las demás leyes convenientes y necesarias para hacer efectivos los derechos y garantías y poner en ejecución los principios, poderes y autoridades establecidos por esta Constitución`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 102, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-105', lawId: 'const-santa-cruz', number: '105', title: 'De la Sanción de las Leyes', originalText: `Las leyes tendrán su origen en proyectos presentados por uno o más Diputados o por el Poder Ejecutivo.`, currentText: `Las leyes tendrán su origen en proyectos presentados por uno o más Diputados o por el Poder Ejecutivo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 103, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-106', lawId: 'const-santa-cruz', number: '106', title: '', originalText: `Sancionada una ley se remitirá al Poder Ejecutivo para que la promulgue o la vete en todo o en parte dentro de los diez y seis días hábiles de su envío, repuntándose promulgada si no se veta dentro del plazo previsto. Si el Poder Ejecutivo promulgase una ley, deberá publicarla en el día inmediato o en su defecto será publicada por el Presidente de la Cámara a Resolución de ésta.`, currentText: `Sancionada una ley se remitirá al Poder Ejecutivo para que la promulgue o la vete en todo o en parte dentro de los diez y seis días hábiles de su envío, repuntándose promulgada si no se veta dentro del plazo previsto. Si el Poder Ejecutivo promulgase una ley, deberá publicarla en el día inmediato o en su defecto será publicada por el Presidente de la Cámara a Resolución de ésta.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 104, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-107', lawId: 'const-santa-cruz', number: '107', title: '', originalText: `Vetada en todo o en parte volverá con sus objeciones a la Cámara que en el término de treinta días podrá insistir en su sanción con dos tercios de votos de sus miembros presentes, en cuyo caso será promulgada, o aceptar las objeciones por simple mayoría. El veto parcial no invalida el resto de la ley que deberá ser promulgada y entrará en vigor en la parte no afectada por el mismo.`, currentText: `Vetada en todo o en parte volverá con sus objeciones a la Cámara que en el término de treinta días podrá insistir en su sanción con dos tercios de votos de sus miembros presentes, en cuyo caso será promulgada, o aceptar las objeciones por simple mayoría. El veto parcial no invalida el resto de la ley que deberá ser promulgada y entrará en vigor en la parte no afectada por el mismo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 105, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-108', lawId: 'const-santa-cruz', number: '108', title: '', originalText: `Ningún Proyecto de Ley desechado totalmente por la Cámara podrá tratarse nuevamente en las sesiones del mismo año. Todo proyecto no sancionado en el curso de dos años legislativos se considerará rechazado.`, currentText: `Ningún Proyecto de Ley desechado totalmente por la Cámara podrá tratarse nuevamente en las sesiones del mismo año. Todo proyecto no sancionado en el curso de dos años legislativos se considerará rechazado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 106, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-109', lawId: 'const-santa-cruz', number: '109', title: '', originalText: `La Cámara estará obligada a discutir todo proyecto o petición que le sea presentado con la firma de ciudadanos inscriptos en el Padrón Electoral de la Provincia que alcancen al diez por ciento del mismo.`, currentText: `La Cámara estará obligada a discutir todo proyecto o petición que le sea presentado con la firma de ciudadanos inscriptos en el Padrón Electoral de la Provincia que alcancen al diez por ciento del mismo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 107, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-110', lawId: 'const-santa-cruz', number: '110', title: '', originalText: `En la sanción de las leyes se usará la siguiente fórmula: "El Poder Legislativo de la Provincia de Santa Cruz, sanciona con fuerza de ley".`, currentText: `En la sanción de las leyes se usará la siguiente fórmula: "El Poder Legislativo de la Provincia de Santa Cruz, sanciona con fuerza de ley".`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 108, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-111', lawId: 'const-santa-cruz', number: '111', title: 'Organización', originalText: `El Poder Ejecutivo será desempeñado por un ciudadano con el título de Gobernador de la Provincia. Al mismo tiempo y por igual período se elegirá un Vicegobernador.`, currentText: `El Poder Ejecutivo será desempeñado por un ciudadano con el título de Gobernador de la Provincia. Al mismo tiempo y por igual período se elegirá un Vicegobernador.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 109, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-112', lawId: 'const-santa-cruz', number: '112', title: '', originalText: `Para ser elegido Gobernador o Vicegobernador se requiere: 1) Ser argentino nativo o por opción. 2) Ser nativo de la Provincia o tener cinco años de residencia inmediata o diez alternada en ella, salvo ausencia motivada por servicios prestados a la Nación o a la Provincia. 3) Tener como mínimo 30 años de edad.`, currentText: `Para ser elegido Gobernador o Vicegobernador se requiere: 1) Ser argentino nativo o por opción. 2) Ser nativo de la Provincia o tener cinco años de residencia inmediata o diez alternada en ella, salvo ausencia motivada por servicios prestados a la Nación o a la Provincia. 3) Tener como mínimo 30 años de edad.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 110, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-113', lawId: 'const-santa-cruz', number: '113', title: '', originalText: `El Gobernador y Vicegobernador durarán cuatro años en su mandato y cesarán el mismo día en que expire ese período, sin que evento alguno pueda motivar su prórroga, ni que se le complete en caso de interrupción.`, currentText: `El Gobernador y Vicegobernador durarán cuatro años en su mandato y cesarán el mismo día en que expire ese período, sin que evento alguno pueda motivar su prórroga, ni que se le complete en caso de interrupción.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 111, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-114', lawId: 'const-santa-cruz', number: '114', title: '', originalText: `El Gobernador y el Vicegobernador serán elegidos directamente por el pueblo de la Provincia a simple pluralidad de sufragios. Podrán ser reelectos.`, currentText: `El Gobernador y el Vicegobernador serán elegidos directamente por el pueblo de la Provincia a simple pluralidad de sufragios. Podrán ser reelectos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 112, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-115', lawId: 'const-santa-cruz', number: '115', title: '', originalText: `El Vicegobernador reemplaza temporal o definitivamente al Gobernador en caso de muerte, renuncia, destitución, enfermedad, suspensión o ausencia. Para reemplazar al Vicegobernador en los mismos casos serán llamados en su orden el Vicepresidente Primero y Segundo de la Cámara y el Presidente del Tribunal Superior de Justicia. Cuando la acefalía comprenda al Gobernador y Vicegobernador se elegirán nuevamente en la elección inmediata para la renovación de la Cámara.`, currentText: `El Vicegobernador reemplaza temporal o definitivamente al Gobernador en caso de muerte, renuncia, destitución, enfermedad, suspensión o ausencia. Para reemplazar al Vicegobernador en los mismos casos serán llamados en su orden el Vicepresidente Primero y Segundo de la Cámara y el Presidente del Tribunal Superior de Justicia. Cuando la acefalía comprenda al Gobernador y Vicegobernador se elegirán nuevamente en la elección inmediata para la renovación de la Cámara.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 113, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-116', lawId: 'const-santa-cruz', number: '116', title: '', originalText: `El Gobernador y Vicegobernador al tomar posesión de sus cargos prestarán juramento ante la Cámara de Diputados de desempeñarlo fielmente de acuerdo a esta Constitución. Si la Camara no alcanzará quórum ese día, el juramento será prestado ante el Tribunal Superior de Justicia.`, currentText: `El Gobernador y Vicegobernador al tomar posesión de sus cargos prestarán juramento ante la Cámara de Diputados de desempeñarlo fielmente de acuerdo a esta Constitución. Si la Camara no alcanzará quórum ese día, el juramento será prestado ante el Tribunal Superior de Justicia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 114, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-117', lawId: 'const-santa-cruz', number: '117', title: '', originalText: `El Poder Ejecutivo tiene por sede la capital de la Provincia. El ciudadano que lo ejerza debe residir en ella. Podrá ausentarse transitoriamente del territorio provincial pero deberá comunicarlo a la Cámara, dejando a cargo del despacho al Vicegobernador o, en ausencia de aquál, a quien corresponda conforme al artículo 115. Si el periodo de ausencia fuere superior a quince días, durante el mismo se conferirá el ejercicio del cargo al Vicegobernador.`, currentText: `El Poder Ejecutivo tiene por sede la capital de la Provincia. El ciudadano que lo ejerza debe residir en ella. Podrá ausentarse transitoriamente del territorio provincial pero deberá comunicarlo a la Cámara, dejando a cargo del despacho al Vicegobernador o, en ausencia de aquál, a quien corresponda conforme al artículo 115. Si el periodo de ausencia fuere superior a quince días, durante el mismo se conferirá el ejercicio del cargo al Vicegobernador.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 115, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-118', lawId: 'const-santa-cruz', number: '118', title: '', originalText: `El Gobernador tendrá el tratamiento de "Exelencia" y tanto él como el Vicegobernador gozarán del sueldo que determine la ley el cual no podrá ser alterado mientras dure su mandato. No podrán ejercer otro empleo ni recibir emolumento alguno de la Provincia o de la Nación. Una vez aceptado el cargo, el Gobernador y el Vicegobernador electos gozarán de las inmunidades personales que esta Constitución establece para los Diputados`, currentText: `El Gobernador tendrá el tratamiento de "Exelencia" y tanto él como el Vicegobernador gozarán del sueldo que determine la ley el cual no podrá ser alterado mientras dure su mandato. No podrán ejercer otro empleo ni recibir emolumento alguno de la Provincia o de la Nación. Una vez aceptado el cargo, el Gobernador y el Vicegobernador electos gozarán de las inmunidades personales que esta Constitución establece para los Diputados`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 116, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-119', lawId: 'const-santa-cruz', number: '119', title: 'Atribuciones y Deberes del Poder Ejecutivo', originalText: `El Gobernador es el Jefe de la Administración Provincial, la representa en todos sus actos y tiene las siguientes atribuciones y deberes: 1) Nombrar y remover los Ministros Secretarios del despacho. 2) Participar en la formación de las leyes con arreglo a esta Constitución, promulgarlas y expedir decretos o reglamentos para su ejecución, sin alterar su espíritu. 3) Iniciar leyes o promover la modificación o derogación de las existentes por medio de proyectos presentados a la Cámara pudiendo tomar parte en la discusión personalmente o por medio de sus Ministros. 4) Celebrar y firmar tratados o convenios con otras Provincias o con la Nación, dando cuenta a la Cámara para su aprobación o rechazo. 5) Nombrar y remover a los empleados de la administración de acuerdo a la ley que se dicte sobre escalafón y estabilidad y a lo dispuesto en los articulos 32, 33 y 124 de esta Constitución. 6) Nombrar con acuerdo de la Cámara todos los magistrados y funcionarios para quienes esta Constitución y las leyes determinen tal requisito. En el receso de la Cámara podra designarlos en comisión, pero cesarán si no se les presta acuerdo dentro de los treinta días de iniciadas sus sesiones ordinarias. 7) Recaudar los impuestos y rentas de la Provincia y decretar su inversión conforme a las leyes del presupuesto y contabilidad y al Código Fiscal. 8) Informar a la Cámara sobre el estado de la Administración mediante un mensaje que hará conocer en la sesión inaugural del periodo ordinario o en cualquiera del mes de marzo si hubiere tenido impedimento fundado. 9) Proponer a la Cámara en terna, por orden alfabético y en pliego abierto a los miembros del Tribunal Superior de Justicia, la que designará en sesión y votación secreta el que ha de ser nombrado. 10) Convocar a la Cámara a sesiones extraordinarias determinando el objeto de las mismas. 11) Convocar al pueblo de la Provincia a todas las elecciones en la oportunidad debida, sin que por ningún motivo pueda diferirlas. 12) Indultar y conmutar penas, previo informe de los Tribunales. 13) Tomar las medidas necesarias para mantener y conservar la paz y el orden público, por todos los medios que no estén expresamente prohibidos por esta Constitución y leyes vigentes. 14) Prestar auxilio de la fuerza pública cuando le sea solicitado por los Tribunales de Justicia, autoridades y funcionarios que por esta Constitución o por las leyes que en su consecuencia se dicten, estén autorizados para hacer uso de ésta. 15) Presentar la ley de presupuesto para el año siguiente acompañada del cálculo de recursos y dar cuenta del uso y ejercicio del presupuesto anterior, antes del 31 de agosto. 16) Ningún funcionario que necesite acuerdo para su nombramiento, puede ser removido sin el mismo requisito, exceptuándose aquellos que por esta Constitución estén sujetos a un procedimiento especial. 17) Celebrar contratos con empresas particulares, necesarios para fines de utilidad pública, los que estarán sujetos a aprobación de la Cámara. 18) Tomar todas las medidas necesarias para hacer efectivos los derechos, deberes y garantías de esta Constitución, y para el buen orden de la Administración y los servicios, en cuanto no sean atribuciones de otros poderes o autoridades creadas por esta Constitución`, currentText: `El Gobernador es el Jefe de la Administración Provincial, la representa en todos sus actos y tiene las siguientes atribuciones y deberes: 1) Nombrar y remover los Ministros Secretarios del despacho. 2) Participar en la formación de las leyes con arreglo a esta Constitución, promulgarlas y expedir decretos o reglamentos para su ejecución, sin alterar su espíritu. 3) Iniciar leyes o promover la modificación o derogación de las existentes por medio de proyectos presentados a la Cámara pudiendo tomar parte en la discusión personalmente o por medio de sus Ministros. 4) Celebrar y firmar tratados o convenios con otras Provincias o con la Nación, dando cuenta a la Cámara para su aprobación o rechazo. 5) Nombrar y remover a los empleados de la administración de acuerdo a la ley que se dicte sobre escalafón y estabilidad y a lo dispuesto en los articulos 32, 33 y 124 de esta Constitución. 6) Nombrar con acuerdo de la Cámara todos los magistrados y funcionarios para quienes esta Constitución y las leyes determinen tal requisito. En el receso de la Cámara podra designarlos en comisión, pero cesarán si no se les presta acuerdo dentro de los treinta días de iniciadas sus sesiones ordinarias. 7) Recaudar los impuestos y rentas de la Provincia y decretar su inversión conforme a las leyes del presupuesto y contabilidad y al Código Fiscal. 8) Informar a la Cámara sobre el estado de la Administración mediante un mensaje que hará conocer en la sesión inaugural del periodo ordinario o en cualquiera del mes de marzo si hubiere tenido impedimento fundado. 9) Proponer a la Cámara en terna, por orden alfabético y en pliego abierto a los miembros del Tribunal Superior de Justicia, la que designará en sesión y votación secreta el que ha de ser nombrado. 10) Convocar a la Cámara a sesiones extraordinarias determinando el objeto de las mismas. 11) Convocar al pueblo de la Provincia a todas las elecciones en la oportunidad debida, sin que por ningún motivo pueda diferirlas. 12) Indultar y conmutar penas, previo informe de los Tribunales. 13) Tomar las medidas necesarias para mantener y conservar la paz y el orden público, por todos los medios que no estén expresamente prohibidos por esta Constitución y leyes vigentes. 14) Prestar auxilio de la fuerza pública cuando le sea solicitado por los Tribunales de Justicia, autoridades y funcionarios que por esta Constitución o por las leyes que en su consecuencia se dicten, estén autorizados para hacer uso de ésta. 15) Presentar la ley de presupuesto para el año siguiente acompañada del cálculo de recursos y dar cuenta del uso y ejercicio del presupuesto anterior, antes del 31 de agosto. 16) Ningún funcionario que necesite acuerdo para su nombramiento, puede ser removido sin el mismo requisito, exceptuándose aquellos que por esta Constitución estén sujetos a un procedimiento especial. 17) Celebrar contratos con empresas particulares, necesarios para fines de utilidad pública, los que estarán sujetos a aprobación de la Cámara. 18) Tomar todas las medidas necesarias para hacer efectivos los derechos, deberes y garantías de esta Constitución, y para el buen orden de la Administración y los servicios, en cuanto no sean atribuciones de otros poderes o autoridades creadas por esta Constitución`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 117, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-120', lawId: 'const-santa-cruz', number: '120', title: 'De los Ministros Secretarios', originalText: `Para ser nombrado Ministro se requieren las mismas cualidades que esta Constitución exige para ser elegido Diputado y gozarán de iguales privilegios e inmunidades. Una ley especial determinará su número y deslindará las funciones adscriptas al despacho de cada uno de los Ministerios.`, currentText: `Para ser nombrado Ministro se requieren las mismas cualidades que esta Constitución exige para ser elegido Diputado y gozarán de iguales privilegios e inmunidades. Una ley especial determinará su número y deslindará las funciones adscriptas al despacho de cada uno de los Ministerios.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 118, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-121', lawId: 'const-santa-cruz', number: '121', title: '', originalText: `Los Ministros refrendarán con su firma los actos del Poder Ejecutivo, los que carecerán de validéz sin ese requisito, excepto cuando se trate de la propia remoción. Serán responsables de los actos que refrenden y solidariamente de los que acuerden con sus colegas. Podrán tomar por si solos resoluciones referentes al régimen económico y administrativo de su Departamento y concurrir a la Cámara participando de sus debates sin voto y sin perjuicio de lo establecido en el articulo 100.`, currentText: `Los Ministros refrendarán con su firma los actos del Poder Ejecutivo, los que carecerán de validéz sin ese requisito, excepto cuando se trate de la propia remoción. Serán responsables de los actos que refrenden y solidariamente de los que acuerden con sus colegas. Podrán tomar por si solos resoluciones referentes al régimen económico y administrativo de su Departamento y concurrir a la Cámara participando de sus debates sin voto y sin perjuicio de lo establecido en el articulo 100.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 119, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-122', lawId: 'const-santa-cruz', number: '122', title: '', originalText: `Los Ministros gozarán del sueldo que les fije la ley de Presupuesto en la forma prescripta por el artículo 118`, currentText: `Los Ministros gozarán del sueldo que les fije la ley de Presupuesto en la forma prescripta por el artículo 118`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 120, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-123', lawId: 'const-santa-cruz', number: '123', title: 'Del Tribunal de Cuentas', originalText: `Un Tribunal de Cuentas, tendrá a su cargo el examen de las cuentas de percepción e inversión de las rentas públicas provinciales y municipales. La ley determinará su organización y constitución, así como la obligación de comunicar inmediatamente a la Cámara los actos que realice el Poder Ejecutivo contrariando la expresa oposición del Tribunal. Sus miembros serán designados por el Poder Ejecutivo con acuerdo de la Camara, salvo uno que lo será a propuesta del partido político que constituya la primera minoría en la Provincia`, currentText: `Un Tribunal de Cuentas, tendrá a su cargo el examen de las cuentas de percepción e inversión de las rentas públicas provinciales y municipales. La ley determinará su organización y constitución, así como la obligación de comunicar inmediatamente a la Cámara los actos que realice el Poder Ejecutivo contrariando la expresa oposición del Tribunal. Sus miembros serán designados por el Poder Ejecutivo con acuerdo de la Camara, salvo uno que lo será a propuesta del partido político que constituya la primera minoría en la Provincia`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 121, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-124', lawId: 'const-santa-cruz', number: '124', title: 'Del Tribunal Disciplinario', originalText: `Para la disciplina de la administración pública se organizará por ley un Tribunal Disciplinario. Ningún empleado público sera declarado cesante ni exonerado sino por resolución de este Tribunal. Sus miembros serán nombrados por el Poder Ejecutivo con acuerdo de la Cámara, salvo uno que lo sera a propuesta del Partido Político que constituya la primera minoría en la Provincia`, currentText: `Para la disciplina de la administración pública se organizará por ley un Tribunal Disciplinario. Ningún empleado público sera declarado cesante ni exonerado sino por resolución de este Tribunal. Sus miembros serán nombrados por el Poder Ejecutivo con acuerdo de la Cámara, salvo uno que lo sera a propuesta del Partido Político que constituya la primera minoría en la Provincia`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 122, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-125', lawId: 'const-santa-cruz', number: '125', title: 'De la Fiscalía de Estado', originalText: `El Fiscal de Estado tendrá a su cargo el control de legalidad de los actos administrativos y la defensa del patrimonio provincial. Es parte necesaria y legítima en todo proceso en que se controviertan intereses de la Provincia y en los que ésta actúe de cualquier forma. Tendrá personería para demandar la nulidad de leyes, decretos, reglamentos o resoluciones contrarios a las prescripciones de la Constitución Provincial en el solo interés de la ley o en la defensa de los intereses fiscales. Será designado por el Poder Ejecutivo con el acuerdo de la Cámara, gozará de inamovilidad mientras dure su buena conducta y solo podrá ser removido por las causales y el procedimiento del juicio político; finalizará en sus funciones al cesar en su mandato quien lo designó, pudiendo ser redesignado. Para ser Fiscal de Estado se requerirán las mismas condiciones que las exigidas a los miembros del Tribunal Superior de Justicia, contará con iguales inhabilidades, derechos, incompatibilidades e inmunidades que aquellos, debiendo ser natural de la Provincia o contar con una residencia continua y permanente de cuatro años inmediatos anteriores a su desiganción`, currentText: `El Fiscal de Estado tendrá a su cargo el control de legalidad de los actos administrativos y la defensa del patrimonio provincial. Es parte necesaria y legítima en todo proceso en que se controviertan intereses de la Provincia y en los que ésta actúe de cualquier forma. Tendrá personería para demandar la nulidad de leyes, decretos, reglamentos o resoluciones contrarios a las prescripciones de la Constitución Provincial en el solo interés de la ley o en la defensa de los intereses fiscales. Será designado por el Poder Ejecutivo con el acuerdo de la Cámara, gozará de inamovilidad mientras dure su buena conducta y solo podrá ser removido por las causales y el procedimiento del juicio político; finalizará en sus funciones al cesar en su mandato quien lo designó, pudiendo ser redesignado. Para ser Fiscal de Estado se requerirán las mismas condiciones que las exigidas a los miembros del Tribunal Superior de Justicia, contará con iguales inhabilidades, derechos, incompatibilidades e inmunidades que aquellos, debiendo ser natural de la Provincia o contar con una residencia continua y permanente de cuatro años inmediatos anteriores a su desiganción`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 123, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-126', lawId: 'const-santa-cruz', number: '126', title: 'Organizacion', originalText: `El Poder Judicial de la Provincia será desempeñado por un Tribunal Superior de Justicia compuesto por un número impar de miembros no inferior a tres, y los demás Tribunales establecidos por esta Constitución o por la Cámara en ejercicio de sus atribuciones.`, currentText: `El Poder Judicial de la Provincia será desempeñado por un Tribunal Superior de Justicia compuesto por un número impar de miembros no inferior a tres, y los demás Tribunales establecidos por esta Constitución o por la Cámara en ejercicio de sus atribuciones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 124, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-127', lawId: 'const-santa-cruz', number: '127', title: '', originalText: `Para ser miembro del Tribunal Superior de Justicia se requiere: 1) Ser argentino nativo o por opción. 2) Ser mayor de treinta años. 3) Ser abogado con seis años de ejercicio en la profesión o de funciones judiciales. Los requisitos para los Jueces inferiores y demás funcionarios se fijarán en la respectiva ley orgánica.`, currentText: `Para ser miembro del Tribunal Superior de Justicia se requiere: 1) Ser argentino nativo o por opción. 2) Ser mayor de treinta años. 3) Ser abogado con seis años de ejercicio en la profesión o de funciones judiciales. Los requisitos para los Jueces inferiores y demás funcionarios se fijarán en la respectiva ley orgánica.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 125, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-128', lawId: 'const-santa-cruz', number: '128', title: '', originalText: `Los miembros del Tribunal Superior de Justicia durarán en su cargo mientras dure su buena conducta no pudiendo ser removidos sino por juicio político. Recibirán por sus servicios una retribución que determinará la ley y no podra ser disminuida mientras duren en sus funciones.`, currentText: `Los miembros del Tribunal Superior de Justicia durarán en su cargo mientras dure su buena conducta no pudiendo ser removidos sino por juicio político. Recibirán por sus servicios una retribución que determinará la ley y no podra ser disminuida mientras duren en sus funciones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 126, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-128 bis', lawId: 'const-santa-cruz', number: '128 bis', title: '', originalText: `Un Consejo de la Magistratura, regulado por una ley especial, tendrá a su cargo la función de la selección vinculante por concursos públicos de ternas de postulantes a las magistraturas inferiores. Esta selección deberá realizarse mediante procedimientos que garanticen adecuada publicidad, aplicando criterios objetivos predeterminados de evaluación, privilegiando la solvencia moral, la idoneidad, el respeto por las instituciones democráticas y los derechos humanos. Será integrado periódicamente, preservando la pluralidad, la diversidad y el equilibrio entre sectores evitando hegemonías por representantes de los órganos políticos resultantes de la elección popular del Poder Judicial, de los magistrados y funcionarios, de los empleados de la justicia y de los abogados de la matrícula. La ley establecerá también la forma que se integrará al Consejo una representación electa directamente por el pueblo de la Provincia.`, currentText: `Un Consejo de la Magistratura, regulado por una ley especial, tendrá a su cargo la función de la selección vinculante por concursos públicos de ternas de postulantes a las magistraturas inferiores. Esta selección deberá realizarse mediante procedimientos que garanticen adecuada publicidad, aplicando criterios objetivos predeterminados de evaluación, privilegiando la solvencia moral, la idoneidad, el respeto por las instituciones democráticas y los derechos humanos. Será integrado periódicamente, preservando la pluralidad, la diversidad y el equilibrio entre sectores evitando hegemonías por representantes de los órganos políticos resultantes de la elección popular del Poder Judicial, de los magistrados y funcionarios, de los empleados de la justicia y de los abogados de la matrícula. La ley establecerá también la forma que se integrará al Consejo una representación electa directamente por el pueblo de la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 127, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-129', lawId: 'const-santa-cruz', number: '129', title: '', originalText: `Los magistrados de los tribunales inferiores y funcionarios de los ministerios públicos, podrán ser acusados por cualquier habitante ante un Tribunal de Enjuiciamiento formado por un miembro del Tribunal Superior, un Diputado Letrado, si lo hubiere, y un letrado del Foro Provincial elegido por sorteo efectuado por el Tribunal Superior. Si no hubiere Diputado Letrado será reemplazado por otro miembro del Tribunal Superior. El acusado continuará en el ejercicio de sus funciones si el Tribunal no resolviera lo contrario. El fallo deberá expedirse dentro de los sesenta días a contar desde la admisión de la demanda. El Tribunal se pronunciará siempre en pleno y por mayoría absoluta de sus miembros.`, currentText: `Los magistrados de los tribunales inferiores y funcionarios de los ministerios públicos, podrán ser acusados por cualquier habitante ante un Tribunal de Enjuiciamiento formado por un miembro del Tribunal Superior, un Diputado Letrado, si lo hubiere, y un letrado del Foro Provincial elegido por sorteo efectuado por el Tribunal Superior. Si no hubiere Diputado Letrado será reemplazado por otro miembro del Tribunal Superior. El acusado continuará en el ejercicio de sus funciones si el Tribunal no resolviera lo contrario. El fallo deberá expedirse dentro de los sesenta días a contar desde la admisión de la demanda. El Tribunal se pronunciará siempre en pleno y por mayoría absoluta de sus miembros.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 128, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-130', lawId: 'const-santa-cruz', number: '130', title: '', originalText: `Ningún miembro del Poder Judicial podrá actuar en política, afiliarse a partidos, o ejercer dentro o fuera de la provincia profesión o empleo alguno salvo la docencia`, currentText: `Ningún miembro del Poder Judicial podrá actuar en política, afiliarse a partidos, o ejercer dentro o fuera de la provincia profesión o empleo alguno salvo la docencia`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 129, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-131', lawId: 'const-santa-cruz', number: '131', title: 'Atribuciones', originalText: `Corresponde al Poder Judicial el conocimiento y decisión de las controversias que versen sobre puntos regidos por esta Constitución, tratados y más leyes de la Provincia, así como aquellos en que le corresponda entender de acuerdo con las leyes de la Nación.`, currentText: `Corresponde al Poder Judicial el conocimiento y decisión de las controversias que versen sobre puntos regidos por esta Constitución, tratados y más leyes de la Provincia, así como aquellos en que le corresponda entender de acuerdo con las leyes de la Nación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 130, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-132', lawId: 'const-santa-cruz', number: '132', title: '', originalText: `Corresponde al Superior Tribunal de Justicia: 1) Conocer y resolver originaria y exclusivamente las contiendas de competencias entre poderes públicos de la Provincia; entre éstos y alguna Municipalidad; entre dos o más Municipalidades; los conflictos internos de éstas; y los que se susciten entre Tribunales Inferiores o entre uno de éstos y cualquier autoridad ejecutiva. 2) Decidir en única instancia y en juicio pleno en las causas contencioso-administrativas previa denegación, expresa o tácita del reconocimiento de los derechos que se gestionen. Habra denegación tácita cuando no se resolviere definitivamente dentro de tres meses de encontrarse el expediente en estado de decisión. En las causas contencioso-administrativas, el Superior Tribunal tendrá facultades de hacer cumplir directamente su sentencia por las oficinas y empleados respectivos, si la autoridad administrativa no lo hiciere dentro de los sesenta días de la notificación. 3) Ejercer la jurisdicción originaria y de apelación para conocer y resolver acerca de la constitucionalidad de las leyes, decretos, resoluciones, reglamentos y ordenanzas que estatuyan sobre materia regida por esta Constitución y se cotroviertan por parte interesada. 4) Decidir en grado de apelación sobre las causas resueltas por los Tribunales Inferiores, de acuerdo con las leyes procesales que se dicten.`, currentText: `Corresponde al Superior Tribunal de Justicia: 1) Conocer y resolver originaria y exclusivamente las contiendas de competencias entre poderes públicos de la Provincia; entre éstos y alguna Municipalidad; entre dos o más Municipalidades; los conflictos internos de éstas; y los que se susciten entre Tribunales Inferiores o entre uno de éstos y cualquier autoridad ejecutiva. 2) Decidir en única instancia y en juicio pleno en las causas contencioso-administrativas previa denegación, expresa o tácita del reconocimiento de los derechos que se gestionen. Habra denegación tácita cuando no se resolviere definitivamente dentro de tres meses de encontrarse el expediente en estado de decisión. En las causas contencioso-administrativas, el Superior Tribunal tendrá facultades de hacer cumplir directamente su sentencia por las oficinas y empleados respectivos, si la autoridad administrativa no lo hiciere dentro de los sesenta días de la notificación. 3) Ejercer la jurisdicción originaria y de apelación para conocer y resolver acerca de la constitucionalidad de las leyes, decretos, resoluciones, reglamentos y ordenanzas que estatuyan sobre materia regida por esta Constitución y se cotroviertan por parte interesada. 4) Decidir en grado de apelación sobre las causas resueltas por los Tribunales Inferiores, de acuerdo con las leyes procesales que se dicten.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 131, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-133', lawId: 'const-santa-cruz', number: '133', title: '', originalText: `Artículo 133: Son también atribuciones del Tribunal Superior: 1) Representar al Poder Judicial y ejercer la superintendencia sobre la administración de justicia. 2) Nombrar y remover los empleados subalternos del Poder Judicial. 3) Remover los Jueces de Paz. 4) Dictar reglamentos para el buen orden y disciplina de la administración de justicia. 5) Evacuar los informes que le sean requeridos por los Poderes Ejecutivo y Legislativo. 6) Nombrar y remover los empleados judiciales. Comunicar al Poder Ejecutivo su número y proponer sus dotaciones para que solicite a la Cámara su creación`, currentText: `Artículo 133: Son también atribuciones del Tribunal Superior: 1) Representar al Poder Judicial y ejercer la superintendencia sobre la administración de justicia. 2) Nombrar y remover los empleados subalternos del Poder Judicial. 3) Remover los Jueces de Paz. 4) Dictar reglamentos para el buen orden y disciplina de la administración de justicia. 5) Evacuar los informes que le sean requeridos por los Poderes Ejecutivo y Legislativo. 6) Nombrar y remover los empleados judiciales. Comunicar al Poder Ejecutivo su número y proponer sus dotaciones para que solicite a la Cámara su creación`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 132, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-134', lawId: 'const-santa-cruz', number: '134', title: 'De los Jueces de Paz', originalText: `Una ley establecerá Juzgados de Paz en toda la Provincia teniendo en cuenta sus divisiones administrativas, su extensión y su población; fijará la competencia de dichos juzgados y las calidades que deberán reunir sus titulares.`, currentText: `Una ley establecerá Juzgados de Paz en toda la Provincia teniendo en cuenta sus divisiones administrativas, su extensión y su población; fijará la competencia de dichos juzgados y las calidades que deberán reunir sus titulares.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 133, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-135', lawId: 'const-santa-cruz', number: '135', title: '', originalText: `Los Jueces de Paz serán designados por el Poder Ejecutivo a propuesta interna de las respectivas Municipalidades y Comisiones de Fomento, donde las hubiere. Seran inamovibles mientras dure su buena conducta y solo podrán ser removidos por el Tribunal Superior de Justicia.`, currentText: `Los Jueces de Paz serán designados por el Poder Ejecutivo a propuesta interna de las respectivas Municipalidades y Comisiones de Fomento, donde las hubiere. Seran inamovibles mientras dure su buena conducta y solo podrán ser removidos por el Tribunal Superior de Justicia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 134, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-136', lawId: 'const-santa-cruz', number: '136', title: '', originalText: `En las poblaciones de menos de tres mil habitantes se podrán atribuir a los Jueces de Paz funciones administrativas`, currentText: `En las poblaciones de menos de tres mil habitantes se podrán atribuir a los Jueces de Paz funciones administrativas`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 135, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-137', lawId: 'const-santa-cruz', number: '137', title: 'Juicio Político', originalText: `El Gobernador, el Vicegobernador, sus reemplazantes legales, cuando ejerzan el Poder Ejecutivo, los Ministros y los Magistrados del Tribunal Superior de Justicia están sujetos a juicio político. Seran causas de juicio político: 1) Incapacidad física o mental sobreviniente. 2) Delitos en el desempeño de su función. 3) Falta de cumplimiento de los deberes de su cargo. 4) Delitos comunes.`, currentText: `El Gobernador, el Vicegobernador, sus reemplazantes legales, cuando ejerzan el Poder Ejecutivo, los Ministros y los Magistrados del Tribunal Superior de Justicia están sujetos a juicio político. Seran causas de juicio político: 1) Incapacidad física o mental sobreviniente. 2) Delitos en el desempeño de su función. 3) Falta de cumplimiento de los deberes de su cargo. 4) Delitos comunes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 136, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-139', lawId: 'const-santa-cruz', number: '139', title: '', originalText: `El juicio político se ajustará al siguiente procedimiento que podrá ser reglamentado por ley: 1) Division por sorteo de la Cámara de Diputados, en Sala Acusadora y Sala Juzgadora, que tendrá lugar la primera sesión ordinaria de cada año. 2) Término de cuarenta días para que la Sala Acusadora acepte por dos tercios de votos de sus miembros presentes o rechace la sanción. 3) Término de treinta días para que la Sala Juzgadora resuelva en definitiva debiendo dictarse el fallo condenatorio por dos tercios de votos de los miembros presentes. 4) Votación nominal de ambas salas. 5) Amplias facultades de investigación. 6) Garantías de la defensa y prueba 7) Suspensión del acusado al aceptarse la acusación por la primera sala, y retorno al ejercicio de sus funciones, con reintegro de haberes, al dictarse fallo absolutorio o vencer el término sin fallo alguno`, currentText: `El juicio político se ajustará al siguiente procedimiento que podrá ser reglamentado por ley: 1) Division por sorteo de la Cámara de Diputados, en Sala Acusadora y Sala Juzgadora, que tendrá lugar la primera sesión ordinaria de cada año. 2) Término de cuarenta días para que la Sala Acusadora acepte por dos tercios de votos de sus miembros presentes o rechace la sanción. 3) Término de treinta días para que la Sala Juzgadora resuelva en definitiva debiendo dictarse el fallo condenatorio por dos tercios de votos de los miembros presentes. 4) Votación nominal de ambas salas. 5) Amplias facultades de investigación. 6) Garantías de la defensa y prueba 7) Suspensión del acusado al aceptarse la acusación por la primera sala, y retorno al ejercicio de sus funciones, con reintegro de haberes, al dictarse fallo absolutorio o vencer el término sin fallo alguno`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 137, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-140', lawId: 'const-santa-cruz', number: '140', title: 'Organización', originalText: `En la Capital de la Provincia y en cada centro poblado que cuente con número mínimo de mil habitantes se constituirá un municipio encargado de la administración de los intereses locales.`, currentText: `En la Capital de la Provincia y en cada centro poblado que cuente con número mínimo de mil habitantes se constituirá un municipio encargado de la administración de los intereses locales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 138, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-141', lawId: 'const-santa-cruz', number: '141', title: '', originalText: `Esta Constitución reconoce autonomía política, administrativa, económica y financiera a todos los municipios. Aquellos que dicten su Carta Orgánica Municipal, gozarán además de autonomía institucional. La autonomía municipal que aqui se reconoce no podrá ser limitada por ley ni autoridad alguna.`, currentText: `Esta Constitución reconoce autonomía política, administrativa, económica y financiera a todos los municipios. Aquellos que dicten su Carta Orgánica Municipal, gozarán además de autonomía institucional. La autonomía municipal que aqui se reconoce no podrá ser limitada por ley ni autoridad alguna.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 139, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-142', lawId: 'const-santa-cruz', number: '142', title: '', originalText: `Aquellos Municipios que así lo decidan, quedan habilitados para el dictado de sus propias cartas orgánicas, que deberán ser sancionadas por convenciones convocadas por la autoridad ejecutiva local, en virtud de ordenanza sancionada a tal efecto con una mayoría de por lo menos cuatro concejales, salvo en la Capital de la Provincia donde se requerirá el voto favorable de cinco. La estructura que fije la Carta Orgánica se adecuará a las posibilidades presupuestarias de cada Municipalidad, deberá propender al autofinanciamiento y a la desconcentración operativa de sus funciones, evitando generar un mayor peso impositivo sobre los habitantes de la ciudad quedando prohibida la creación de imposiciones especiales destinadas a solventarla.`, currentText: `Aquellos Municipios que así lo decidan, quedan habilitados para el dictado de sus propias cartas orgánicas, que deberán ser sancionadas por convenciones convocadas por la autoridad ejecutiva local, en virtud de ordenanza sancionada a tal efecto con una mayoría de por lo menos cuatro concejales, salvo en la Capital de la Provincia donde se requerirá el voto favorable de cinco. La estructura que fije la Carta Orgánica se adecuará a las posibilidades presupuestarias de cada Municipalidad, deberá propender al autofinanciamiento y a la desconcentración operativa de sus funciones, evitando generar un mayor peso impositivo sobre los habitantes de la ciudad quedando prohibida la creación de imposiciones especiales destinadas a solventarla.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 140, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-143', lawId: 'const-santa-cruz', number: '143', title: '', originalText: `La Convención Municipal se integrará por el doble del número de concejales elegidos por voto directo y por el sistema de representación proporcional. Para ser convencional se requerirán las mismas condiciones que para ser concejal. La ordenanza que declare la necesidad del dictado de la Carta Orgánica fijará las inhabilidades e incompatibilidades para ser electo convencional municipal y podrá establecer mayorías especiales para la sancion de aquella.`, currentText: `La Convención Municipal se integrará por el doble del número de concejales elegidos por voto directo y por el sistema de representación proporcional. Para ser convencional se requerirán las mismas condiciones que para ser concejal. La ordenanza que declare la necesidad del dictado de la Carta Orgánica fijará las inhabilidades e incompatibilidades para ser electo convencional municipal y podrá establecer mayorías especiales para la sancion de aquella.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 141, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-144', lawId: 'const-santa-cruz', number: '144', title: '', originalText: `Los Municipios deberán contar con un Ejecutivo unipersonal y un Cuerpo Deliberativo, fijado en cinco miembros, salvo en la Capital donde constará de siete. Para ocupar tales cargos se requerirán los mismos requisitos que para ser diputados y los que se establezcan en función de la residencia minima en la localidad. Durarán cuatro años en el ejercicio de su función, pudiendo ser reelegidos.`, currentText: `Los Municipios deberán contar con un Ejecutivo unipersonal y un Cuerpo Deliberativo, fijado en cinco miembros, salvo en la Capital donde constará de siete. Para ocupar tales cargos se requerirán los mismos requisitos que para ser diputados y los que se establezcan en función de la residencia minima en la localidad. Durarán cuatro años en el ejercicio de su función, pudiendo ser reelegidos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 142, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-145', lawId: 'const-santa-cruz', number: '145', title: '', originalText: `Las Cartas Orgánicas deberán asegurar: 1) Los principios del régimen representativo y democrático. 2) La elección directa y a simple pluralidad de sufragios del órgano ejecutivo y la representación proporcional en los cuerpos colegiados. 3) El procedimiento para su reforma. 4) Los derechos de consulta e iniciativa popular. 5) Un sistema de contralor de las cuentas públicas. 6) El reconocimiento de juntas vecinales y comisiones de vecinos,con participación en la gestión municipal y preservación del régimen representativo y republicano. 7) Los principios, declaraciones y garantías de esta Constitución.`, currentText: `Las Cartas Orgánicas deberán asegurar: 1) Los principios del régimen representativo y democrático. 2) La elección directa y a simple pluralidad de sufragios del órgano ejecutivo y la representación proporcional en los cuerpos colegiados. 3) El procedimiento para su reforma. 4) Los derechos de consulta e iniciativa popular. 5) Un sistema de contralor de las cuentas públicas. 6) El reconocimiento de juntas vecinales y comisiones de vecinos,con participación en la gestión municipal y preservación del régimen representativo y republicano. 7) Los principios, declaraciones y garantías de esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 143, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-146', lawId: 'const-santa-cruz', number: '146', title: '', originalText: `La Legislatura sancionará la Ley Orgánica Municipal para los municipios que no tengan carta orgánica; la que establecerá, conforme lo estatuido por esta Constitución: 1) Las funciones y atribuciones del Intendente y del Concejo Deliberante y el régimen de subrogancia legal del jefe del Departamento Ejecutivo. 2) La libre gestión de las materias de su competencia. 3) La determinación, recaudación e inversión de sus rentas, incluídas las provenientes de la coparticipación que establece el artículo 154 de esta Constitución, cuya distribución entre la Provincia y los Municipios se efectuará en relación directa a las competencias, servicios y funciones de cada una de ellas contemplando criterios objetivos de reparto que aseguren el suministro de un nivel adecuado de servicios a todos; será equitativa, solidaria y dará prioridad al logro de un grado equivalente de desarrollo, calidad de vida e igualdad de oportunidades en todo el territorio.`, currentText: `La Legislatura sancionará la Ley Orgánica Municipal para los municipios que no tengan carta orgánica; la que establecerá, conforme lo estatuido por esta Constitución: 1) Las funciones y atribuciones del Intendente y del Concejo Deliberante y el régimen de subrogancia legal del jefe del Departamento Ejecutivo. 2) La libre gestión de las materias de su competencia. 3) La determinación, recaudación e inversión de sus rentas, incluídas las provenientes de la coparticipación que establece el artículo 154 de esta Constitución, cuya distribución entre la Provincia y los Municipios se efectuará en relación directa a las competencias, servicios y funciones de cada una de ellas contemplando criterios objetivos de reparto que aseguren el suministro de un nivel adecuado de servicios a todos; será equitativa, solidaria y dará prioridad al logro de un grado equivalente de desarrollo, calidad de vida e igualdad de oportunidades en todo el territorio.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 144, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-147', lawId: 'const-santa-cruz', number: '147', title: '', originalText: `Las Municipalidades podrán ser intervenidas por ley: 1) Para asegurar la inmediata constitución de sus autoridades en caso de acefalía total. 2) Para regularizar sus finanzas en los siguientes casos: a.- Cuando el Municipio no cumpliera con los servicios de empréstitos, o cuando de tres ejercicios sucesivos resultara un déficit susceptible de comprometer la estabilidad financiera. b.- Cuando por actos u omisiones se impida la fiscalización de los organismos de control de la legalidad del gasto y de las cuentas municipales.`, currentText: `Las Municipalidades podrán ser intervenidas por ley: 1) Para asegurar la inmediata constitución de sus autoridades en caso de acefalía total. 2) Para regularizar sus finanzas en los siguientes casos: a.- Cuando el Municipio no cumpliera con los servicios de empréstitos, o cuando de tres ejercicios sucesivos resultara un déficit susceptible de comprometer la estabilidad financiera. b.- Cuando por actos u omisiones se impida la fiscalización de los organismos de control de la legalidad del gasto y de las cuentas municipales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 145, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-148', lawId: 'const-santa-cruz', number: '148', title: '', originalText: `En aquellos centros de población que no alcancen el número de mil habitantes, los intereses y servicios de carácter comunal estarán a cargo de Comisiones de Fomento cuya integración y atribuciones serán fijadas por ley.`, currentText: `En aquellos centros de población que no alcancen el número de mil habitantes, los intereses y servicios de carácter comunal estarán a cargo de Comisiones de Fomento cuya integración y atribuciones serán fijadas por ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 146, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-149', lawId: 'const-santa-cruz', number: '149', title: '', originalText: `Los conflictos entre autoridades del Municipio y las cuestiones de competencia que se susciten entre Municipios o entre éstos y la Provincia, serán resueltos en única instancia por el Tribunal Superior de Justicia de la Provincia`, currentText: `Los conflictos entre autoridades del Municipio y las cuestiones de competencia que se susciten entre Municipios o entre éstos y la Provincia, serán resueltos en única instancia por el Tribunal Superior de Justicia de la Provincia`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 147, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-150', lawId: 'const-santa-cruz', number: '150', title: 'Atribuciones', originalText: `En el ámbito territorial que la Legislatura le fije y conforme a criterios técnicos, el Municipio desarrollará su actividad y tendrá competencia en las siguientes materias, sin perjuicio de otras que las leyes le fijen: 1) Gobernar y administrar los intereses públicos locales dirigidos al bien común. 2) Confeccionar y aprobar su presupuesto de gastos y cálculo de recuros, percibiendo y aplicando los impuestos, contribuciones, tasas y precios que fije. 3) Designar y remover a sus funcionarios y empleados. 4) Conservar, administrar y disponer de los bienes que integran el patrimonio municipal. 5) Administrar y distribuir las tierras fiscales ubicadas dentro del ejido municipal. 6) Atender la organización y prestación, por si o por terceros, de los servicios públicos esenciales. 7) Dictar Ordenanzas que traten sobre el plan regulador del desarrollo urbano; apertura y pavimentación de calles; construcción de plazas y paseos; uso de las calles, del subsuelo y del espacio aéreo; seguridad e higiene en la edificación y construcción en general; tráfico, transporte y vialidad urbana. 8) Atender lo inherente a la salubridad; la salud pública y los centros asistenciales; la higiene y moralidad pública; la minoridad, la familia y la ancianidad; la discapacidad y el desamparo; cementerios y servicios fúnebres; faenamiento de animales destinados al consumo; los mercados de abasto y el abastecimiento de productos en las mejores condiciones de calidad y precio, así como la elaboración y venta de alimentos; la creación y el fomento de instituciones de cultura intelectual y física y establecimientos de enseñanza regidos por ordenanzas concordantes con las leyes en la materia; los servicios de previsión y asistencia social. 9) Contraer empréstitos con único destino a obras públicas, con las limitaciones y recaudos que establezca la ley. 10) Velar por la preservación del patrimonio cultural, arquitectónico, arqueológico, histórico y natural. 11) Convocar a la ciudadanía a consulta popular e instrumentar el derecho a la iniciativa popular. 12) Convenir con la Provincia su participación en la administración, gestion y ejecucion de obras y servicios que preste o ejecute en su radio, con la asignación de recursos en su caso, para lograr mayor eficiencia y descentralización operativa. 13) Participar en la elaboración y ejecución de los planes de desarrollo regional y acordar su participación en la realización de obras y la prestación de servicios que le afecten en razón de la zona. 14) Juzgar las contravenciones a las disposiciones que dicte. 15) Publicar mensualmente el estado de los ingresos y egresos y anualmente una memoria sobre el estado de los diversos ramos de la administración. 16) Actuar como agente natural del gobierno provincial y ejercer las facultades que por delegación de la ley o convenios les concedan la Nación o la Provincia. 17) Ejercer la función de coordinación de los esfuerzos de los distintos niveles de gobierno en el ámbito de la ciudad y cualquier otra de interés municipal no prohibida por esta Constitución y que no sea incompatible con facultades de otros poderes del Estado.`, currentText: `En el ámbito territorial que la Legislatura le fije y conforme a criterios técnicos, el Municipio desarrollará su actividad y tendrá competencia en las siguientes materias, sin perjuicio de otras que las leyes le fijen: 1) Gobernar y administrar los intereses públicos locales dirigidos al bien común. 2) Confeccionar y aprobar su presupuesto de gastos y cálculo de recuros, percibiendo y aplicando los impuestos, contribuciones, tasas y precios que fije. 3) Designar y remover a sus funcionarios y empleados. 4) Conservar, administrar y disponer de los bienes que integran el patrimonio municipal. 5) Administrar y distribuir las tierras fiscales ubicadas dentro del ejido municipal. 6) Atender la organización y prestación, por si o por terceros, de los servicios públicos esenciales. 7) Dictar Ordenanzas que traten sobre el plan regulador del desarrollo urbano; apertura y pavimentación de calles; construcción de plazas y paseos; uso de las calles, del subsuelo y del espacio aéreo; seguridad e higiene en la edificación y construcción en general; tráfico, transporte y vialidad urbana. 8) Atender lo inherente a la salubridad; la salud pública y los centros asistenciales; la higiene y moralidad pública; la minoridad, la familia y la ancianidad; la discapacidad y el desamparo; cementerios y servicios fúnebres; faenamiento de animales destinados al consumo; los mercados de abasto y el abastecimiento de productos en las mejores condiciones de calidad y precio, así como la elaboración y venta de alimentos; la creación y el fomento de instituciones de cultura intelectual y física y establecimientos de enseñanza regidos por ordenanzas concordantes con las leyes en la materia; los servicios de previsión y asistencia social. 9) Contraer empréstitos con único destino a obras públicas, con las limitaciones y recaudos que establezca la ley. 10) Velar por la preservación del patrimonio cultural, arquitectónico, arqueológico, histórico y natural. 11) Convocar a la ciudadanía a consulta popular e instrumentar el derecho a la iniciativa popular. 12) Convenir con la Provincia su participación en la administración, gestion y ejecucion de obras y servicios que preste o ejecute en su radio, con la asignación de recursos en su caso, para lograr mayor eficiencia y descentralización operativa. 13) Participar en la elaboración y ejecución de los planes de desarrollo regional y acordar su participación en la realización de obras y la prestación de servicios que le afecten en razón de la zona. 14) Juzgar las contravenciones a las disposiciones que dicte. 15) Publicar mensualmente el estado de los ingresos y egresos y anualmente una memoria sobre el estado de los diversos ramos de la administración. 16) Actuar como agente natural del gobierno provincial y ejercer las facultades que por delegación de la ley o convenios les concedan la Nación o la Provincia. 17) Ejercer la función de coordinación de los esfuerzos de los distintos niveles de gobierno en el ámbito de la ciudad y cualquier otra de interés municipal no prohibida por esta Constitución y que no sea incompatible con facultades de otros poderes del Estado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 148, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-151', lawId: 'const-santa-cruz', number: '151', title: '', originalText: `Como sanción de sus ordenanzas las autoridades municipales podrán imponer multas o arrestos hasta un máximo que fijará la ley. Podrán igualmente por razones de seguridad e higiene, disponer la demolición de construcciones, la clausura y desalojo de locales, y el secuestro, destrucción, decomiso de objetos o mercaderías notoriamente nocivas, para lo cual podrán usar de la fuerza pública y recabar orden de allanamiento`, currentText: `Como sanción de sus ordenanzas las autoridades municipales podrán imponer multas o arrestos hasta un máximo que fijará la ley. Podrán igualmente por razones de seguridad e higiene, disponer la demolición de construcciones, la clausura y desalojo de locales, y el secuestro, destrucción, decomiso de objetos o mercaderías notoriamente nocivas, para lo cual podrán usar de la fuerza pública y recabar orden de allanamiento`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 149, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-152', lawId: 'const-santa-cruz', number: '152', title: 'De los Recursos', originalText: `Las Municipalidades, tendrán rentas y bienes propios, siendo exclusiva su facultad de imposición respecto de personas, cosas o formas de actividad sujetas a jurisdicción municipal, que ejercitará conforme a su ley orgánica y con las limitaciones que ella establezca respecto de sus bases, o para impedir que se sancionen gravámenes incompatibles con los nacionales o provinciales.`, currentText: `Las Municipalidades, tendrán rentas y bienes propios, siendo exclusiva su facultad de imposición respecto de personas, cosas o formas de actividad sujetas a jurisdicción municipal, que ejercitará conforme a su ley orgánica y con las limitaciones que ella establezca respecto de sus bases, o para impedir que se sancionen gravámenes incompatibles con los nacionales o provinciales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 150, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-153', lawId: 'const-santa-cruz', number: '153', title: '', originalText: `Las Municipalidades podrán establecer por sí solas impuestos que graven los bienes inmuebles, que se encuentren en su jurisdicción, excluyendo las mejoras.`, currentText: `Las Municipalidades podrán establecer por sí solas impuestos que graven los bienes inmuebles, que se encuentren en su jurisdicción, excluyendo las mejoras.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 151, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-154', lawId: 'const-santa-cruz', number: '154', title: '', originalText: `Dispondrán también como recursos de los impuestos fiscales que se perciban en su jurisdicción en la proporción que fijará la ley`, currentText: `Dispondrán también como recursos de los impuestos fiscales que se perciban en su jurisdicción en la proporción que fijará la ley`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 152, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-155', lawId: 'const-santa-cruz', number: '155', title: 'De la Reforma de la Constitución', originalText: `La necesidad de la reforma deberá ser declarada por la Cámara de Diputados de la Provincia con el voto de las dos terceras partes al menos de la totalidad de sus miembros; pero no se efectuara sino por medio de una Convención convocada al efecto.`, currentText: `La necesidad de la reforma deberá ser declarada por la Cámara de Diputados de la Provincia con el voto de las dos terceras partes al menos de la totalidad de sus miembros; pero no se efectuara sino por medio de una Convención convocada al efecto.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 153, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-156', lawId: 'const-santa-cruz', number: '156', title: '', originalText: `Cuando la Cámara declare la necesidad de la reforma deberá precisar él o los puntos que deberán ser revisados.`, currentText: `Cuando la Cámara declare la necesidad de la reforma deberá precisar él o los puntos que deberán ser revisados.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 154, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-157', lawId: 'const-santa-cruz', number: '157', title: '', originalText: `Precisados por la Cámara los puntos sobre los que versará la reforma y antes de convocarse al pueblo para la elección de los Constituyentes que han de verificarla, dichos puntos se publicarán durante un mes en los principales periódicos de la Provincia.`, currentText: `Precisados por la Cámara los puntos sobre los que versará la reforma y antes de convocarse al pueblo para la elección de los Constituyentes que han de verificarla, dichos puntos se publicarán durante un mes en los principales periódicos de la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 155, segments: [], amendments: [] },
  { id: 'const-santa-cruz-art-158', lawId: 'const-santa-cruz', number: '158', title: '', originalText: `El número de Convencionales será igual al de Diputados, elegidos en la misma forma y mientras ejerzan su mandato gozarán de las mismas inmunidades que aquéllos. Firmantes DIEZ, Luis Angel - GODOY, Jorge Osmar - SANCHEZ PERUGA, Leogardo-`, currentText: `El número de Convencionales será igual al de Diputados, elegidos en la misma forma y mientras ejerzan su mandato gozarán de las mismas inmunidades que aquéllos. Firmantes DIEZ, Luis Angel - GODOY, Jorge Osmar - SANCHEZ PERUGA, Leogardo-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 156, segments: [], amendments: [] },
];
